INSERT INTO caw_content (slug, title, blocks, palette, nav, footer)
VALUES (
  '',
  'The One-Stop Architect | Chris Amaya',
  '[{"data":{"badge":"STATUS: ACCEPTING 2 CLIENTS FOR Q1","subhead":"Stop gluing your business together with Zapier and hope.\nI build Sovereign Infrastructure that works while you sleep.","cta_href":"#audit","headline":"I ARCHITECT SYSTEMS<br class=\"hidden md:block\" />THAT <span class=\"text-neon\">SCALE AGENCIES</span>.","cta_label":"< DEPLOY_ARCHITECT />","warning_text":"// WARNING: Technical Strategy Session Only. No Sales Fluff."},"block_type":"hero"},{"data":{"body":"You have revenue. You have product-market fit. But your backend is a tangled mess of SaaS subscriptions, broken webhooks, and manual data entry.","title":"The \"Frankenstein\" Stack Is Killing Your Margins.","bullets":["⚠ SALES TEAM IS BLIND (CRM not syncing)","⚠ ZAPIER BILL IS SCALING FASTER THAN REVENUE","⚠ YOU ARE THE BOTTLENECK (Playing CTO instead of CEO)"],"eyebrow":"// SYSTEM_CRITICAL_ERROR","status_text":"_ SYSTEM_UNSTABLE","terminal_logs":[{"msg":"[ERROR] Webhook Timeout: Zapier webhook failed to respond.","time":"09:00:01"},{"msg":"[CRITICAL] Lead Loss: 5 leads failed to sync to GHL.","time":"09:05:23"},{"msg":"[WARN] API Rate Limit Exceeded (Airtable).","time":"09:12:00"}]},"block_type":"terminal_problem"},{"data":{"cards":[{"body":"Self-hosted n8n automation engines that run on your own servers. Zero per-task fees. Infinite scalability.","title":"< INFRASTRUCTURE />","border_color":"neon-blue"},{"body":"Private LLM agents that draft emails, qualify leads, and analyze competitors without leaking data to OpenAI.","title":"< INTELLIGENCE />","border_color":"neon-green"},{"body":"Server-side tracking (CAPI) and attribution dashboards that tell you exactly where your ROAS is coming from.","title":"< REVENUE_PHYSICS />","border_color":"neon-pink"}],"title":"Sovereign Infrastructure","eyebrow":"// THE_FIX"},"block_type":"solution_cards"},{"data":{"body":"Most developers write code to finish a ticket. I design systems to finish the business model. As the founder of <a href=\"https://jumpstartscaling.com\" class=\"text-neon border-b border-[#00FF94]\">Jumpstart Scaling</a>, I have seen the backend of 50+ scaling agencies.","stats":[{"label":"Systems Built","value":"50+"},{"label":"Revenue Supported","value":"$10M+"}],"title":"I Am Not A Freelancer.<br>I Am An Architect."},"block_type":"authority"},{"data":{"title":"Technical Strategy Session","subhead":"Let''s audit your stack and find the bottleneck.","form_title":"INITIATE_HANDSHAKE_PROTOCOL","submit_source":"ChrisAmayaWork"},"block_type":"audit_form"},{"data":{"section_title":"Engineering Resources"},"block_type":"calculator"},{"data":{"section_title":"Let''s Build It Right."},"block_type":"survey"}]'::jsonb,
  'emerald',
  '{"cta":{"href":"#audit","label":"INITIATE_HANDSHAKE"},"portfolio":[{"href":"/#hook","name":"The Problem"},{"href":"/#solution","name":"Architecture"},{"href":"/blog","name":"Blog"},{"href":"/guide/how-i-build","name":"How I Build"},{"href":"/knowledge-base","name":"Knowledge Base"},{"href":"/search","name":"Search"}],"custom_apps":[{"href":"/services/custom-apps/python-api","name":"Python & FastAPI"},{"href":"/services/custom-apps/frontend","name":"Astro & React"},{"href":"/services/custom-apps/full-stack","name":"Full-Stack"},{"href":"/services/custom-apps/database","name":"PostgreSQL"},{"href":"/services/custom-apps/google-apis","name":"Google APIs"},{"href":"/services/custom-apps/wordpress","name":"WordPress"},{"href":"/services/custom-apps/calculators","name":"Calculators"},{"href":"/services/custom-apps/3d-visual","name":"3D & Visual"}],"growth_tools":[{"href":"https://jumpstartscaling.com","name":"Jumpstart Scaling"},{"href":"https://jumpstartscaling.com/services/growth-retainer","name":"Growth Retainer"},{"href":"https://jumpstartscaling.com/services/crm-transformation","name":"CRM Build"}]}'::jsonb,
  '{"tagline":"The Unicorn Developer.","copyright":"Chris Amaya"}'::jsonb
)
ON CONFLICT (slug) DO UPDATE SET
  title = EXCLUDED.title, blocks = EXCLUDED.blocks,
  palette = EXCLUDED.palette, nav = EXCLUDED.nav, footer = EXCLUDED.footer;

INSERT INTO caw_content (slug, title, blocks, palette, nav, footer)
VALUES (
  'about',
  'About | Chris Amaya — Unicorn Developer & Architect',
  '[{"data":{"badge":"ABOUT // ARCHITECT ON RECORD","subhead":"I design sovereign infrastructure that eliminates the Zapier tax, replaces fragile SaaS stacks, and compounds like equity — not expense.","cta_href":"#audit","headline":"I Am Not A<br class=\"hidden md:block\"/>Developer.<br class=\"hidden md:block\"/><span class=\"text-neon\">I Am An Architect.</span>","cta_label":"< DEPLOY_ARCHITECT />","warning_text":"// Q1 capacity: 2 clients. Serious inquiries only."},"block_type":"hero"},{"data":{"body":"<p>Most developers ship features. I ship infrastructure that makes features obsolete. Since 2018 I have designed backend systems, private AI agents, custom CRMs, and data pipelines for agencies doing $500k–$10M/yr in revenue.</p><p class=\"mt-4\">I founded <a href=\"https://jumpstartscaling.com\" class=\"text-neon border-b border-[#00FF94]\">Jumpstart Scaling</a> after noticing a pattern: every agency past $1M had the same bottleneck — their tech stack was a liability, not an asset. Zapier bills ballooning. Webhook failures losing leads. Founders acting as CTO instead of CEO.</p><p class=\"mt-4\">The Unicorn Developer model is the answer: one architect who covers backend, frontend, database, AI, and 3D. No agency markup. No vendor lock-in. No offshore handoff.</p>","stats":[{"label":"Engineering Experience","value":"8yr"},{"label":"Systems Architected","value":"50+"},{"label":"Revenue Supported","value":"$10M+"},{"label":"Open Client Slots","value":"2"}],"title":"The Unicorn Developer Thesis"},"block_type":"authority"},{"data":{"cards":[{"body":"FastAPI, asyncpg, PostgreSQL. Private async engines that process webhooks, sync CRMs, and power dashboards — on your own servers, not Zapier''s.","title":"< BACKEND_SYSTEMS />","border_color":"neon-blue"},{"body":"Private LLMs deployed on your infra. Lead qualification, email drafting, competitor analysis — without leaking data to OpenAI or Anthropic.","title":"< AI_AGENTS />","border_color":"neon-green"},{"body":"Server-side CAPI tracking, attribution dashboards, and funnel calculators. Know exactly where every dollar of ROAS originates.","title":"< REVENUE_INTELLIGENCE />","border_color":"neon-pink"}],"title":"Three Pillars of Sovereign Infrastructure","eyebrow":"// WHAT_I_BUILD"},"block_type":"solution_cards"},{"data":{"body":"Hiring a frontend dev, a backend dev, a DevOps engineer, and an AI consultant for one product is how agencies burn runway.","title":"The Specialist Trap Is Costing You Time and Margin.","bullets":["⚠ 4 specialists = 4 onboarding cycles = 4 communication bottlenecks","⚠ Each dev owns a silo; nobody owns the system","⚠ Integration bugs live in the gaps between specialties"],"eyebrow":"// WHY_UNICORN","status_text":"_ UNICORN_MODE: ONE OWNER, ZERO GAPS","terminal_logs":[{"msg":"[ERROR] Frontend assumes REST endpoint existed. Backend never built it.","time":"11:02"},{"msg":"[WARN] DevOps firewall blocking internal DB port. 3hr outage.","time":"11:09"},{"msg":"[CRITICAL] AI consultant needs DB access. Security audit triggered.","time":"11:44"}]},"block_type":"terminal_problem"},{"data":{"title":"What You Get With One Architect","bullets":[{"icon":"🏗️","text":"Every engagement starts with architecture review. No code before the blueprint is solid.","title":"System Design First"},{"icon":"⚡","text":"Production-grade sprints. No \"agile theater\" — real deployments every two weeks.","title":"14-Day Delivery Cycles"},{"icon":"🔐","text":"You own every server, every repo, every line. No vendor dependencies that can price-hike you.","title":"Sovereign Infra Philosophy"},{"icon":"🤖","text":"If an AI agent touches your leads or financials, it runs on your hardware — not a third-party API.","title":"Private AI by Default"},{"icon":"📊","text":"Server-side tracking from day one. Every conversion tied to a source, channel, and ad set.","title":"Attribution Without Guesswork"},{"icon":"🌐","text":"Backend, frontend, database, DevOps, 3D visuals. One person. One codebase. One invoice.","title":"Full Stack Coverage"}]},"block_type":"icon_bullets"},{"data":{"title":"Technical Strategy Session","subhead":"Let''s map your stack and find the bottleneck.","form_title":"INITIATE_HANDSHAKE_PROTOCOL","submit_source":"ChrisAmayaWork-About"},"block_type":"audit_form"},{"data":{"href":"#audit","text":"Two client slots available for Q1. Serious inquiries only — budget $10k+.","label":"Book a Strategy Call","heading":"Ready to Build Sovereign Infrastructure?"},"block_type":"cta"}]'::jsonb,
  'emerald',
  '{"cta":{"href":"#audit","label":"INITIATE_HANDSHAKE"},"portfolio":[{"href":"/#hook","name":"The Problem"},{"href":"/#solution","name":"Architecture"},{"href":"/blog","name":"Blog & Knowledge Base"},{"href":"/guide/how-i-build","name":"How I Build"},{"href":"/search","name":"Search"}],"custom_apps":[{"href":"/services/custom-apps/python-api","name":"Python & FastAPI"},{"href":"/services/custom-apps/frontend","name":"Astro & React"},{"href":"/services/custom-apps/full-stack","name":"Full-Stack"},{"href":"/services/custom-apps/database","name":"PostgreSQL"},{"href":"/services/custom-apps/google-apis","name":"Google APIs"},{"href":"/services/custom-apps/wordpress","name":"WordPress"},{"href":"/services/custom-apps/calculators","name":"Calculators"},{"href":"/services/custom-apps/3d-visual","name":"3D & Visual"}],"growth_tools":[{"href":"https://jumpstartscaling.com","name":"Jumpstart Scaling"},{"href":"https://jumpstartscaling.com/services/growth-retainer","name":"Growth Retainer"},{"href":"https://jumpstartscaling.com/services/crm-transformation","name":"CRM Build"}]}'::jsonb,
  '{"tagline":"The Unicorn Developer.","copyright":"Chris Amaya"}'::jsonb
)
ON CONFLICT (slug) DO UPDATE SET
  title = EXCLUDED.title, blocks = EXCLUDED.blocks,
  palette = EXCLUDED.palette, nav = EXCLUDED.nav, footer = EXCLUDED.footer;

INSERT INTO caw_content (slug, title, blocks, palette, nav, footer)
VALUES (
  'audit',
  'Technical Audit | Chris Amaya — Free Stack Audit',
  '[{"data":{"badge":"FREE AUDIT // 90 SECONDS","subhead":"90-second audit. Custom architecture roadmap. Zero sales pitch. I tell you exactly what is broken and what to build first.","cta_href":"#audit","headline":"Get Your Free<br class=\"hidden md:block\"/><span class=\"text-neon\">Technical Audit.</span>","cta_label":"< START_AUDIT />","warning_text":"// Serious inquiries only. Budget $10k+."},"block_type":"hero"},{"data":{"body":"After reviewing 50+ agency backends the problems are always the same. The symptoms differ — the root cause does not.","title":"What I Find in 90% of Agency Stacks","bullets":["⚠ AUTOMATION LAYER: Zapier/Make handling critical business logic (not a workflow tool, a liability)","⚠ DATA LAYER: No single source of truth. CRM, Sheets, Airtable, Notion — all out of sync","⚠ TRACKING LAYER: Pixel-only attribution — iOS14 wipes 40–60% of conversion data","⚠ AI LAYER: Using ChatGPT for lead data — violating GDPR and risking IP exposure","⚠ INFRA LAYER: $3,000/mo SaaS stack that could be replaced with a $50/mo VPS"],"eyebrow":"// COMMON_AUDIT_FINDINGS","status_text":"_ AUDIT_COMPLETE: BOTTLENECK IDENTIFIED","terminal_logs":[{"msg":"[SCAN] Zapier: 847 active zaps, 12% error rate, $1,200/mo","time":"AUDIT_01"},{"msg":"[SCAN] CRM sync delay: avg 4.2min. Leads going cold before first contact.","time":"AUDIT_02"},{"msg":"[SCAN] Attribution: 58% of conversions showing as \"direct\" post-iOS14","time":"AUDIT_03"},{"msg":"[CRITICAL] Found: client revenue data passing through 3 third-party APIs","time":"AUDIT_04"}]},"block_type":"terminal_problem"},{"data":{"cards":[{"body":"Visual diagram of your current architecture — every tool, every connection, every single point of failure labeled and prioritized.","title":"< STACK_MAP />","border_color":"neon-blue"},{"body":"Itemized breakdown of what you''re paying vs. what it would cost to self-host. Most clients find $2,000–$5,000/mo in savings.","title":"< COST_ANALYSIS />","border_color":"neon-green"},{"body":"Prioritized list of what to build first, second, and third — with time estimates and expected ROI for each component.","title":"< BUILD_ROADMAP />","border_color":"neon-pink"}],"title":"Your Custom Audit Deliverables","eyebrow":"// WHAT_YOU_GET"},"block_type":"solution_cards"},{"data":{"title":"Who This Audit Is For","bullets":[{"icon":"📈","text":"You have revenue. You have product-market fit. Your tech is the ceiling.","title":"Agencies Doing $500k–$10M/yr"},{"icon":"🔧","text":"You are spending 10 hours a week managing integrations instead of clients.","title":"Founders Acting as CTO"},{"icon":"💰","text":"Your tool stack has a per-seat fee for every person and a per-task fee for every automation.","title":"Teams Paying $2k+/mo in SaaS"},{"icon":"🤖","text":"You need AI agents but cannot use ChatGPT on client data.","title":"Companies Wanting Private AI"},{"icon":"📊","text":"Post-iOS14 your ROAS reporting is guesswork. You need server-side tracking.","title":"Media Buyers Losing Attribution"},{"icon":"🚀","text":"Build it right from day one. Architecture review before line one of code.","title":"Teams Planning a New Product"}]},"block_type":"icon_bullets"},{"data":{"title":"Claim Your Free Technical Audit","subhead":"90 seconds to fill out. I respond with a custom architecture roadmap within 24 hours.","form_title":"REQUEST_AUDIT_PROTOCOL","submit_source":"ChrisAmayaWork-Audit"},"block_type":"audit_form"},{"data":{"href":"#audit","text":"I have done this audit 50+ times. The patterns are predictable. The fixes are buildable.","label":"Get My Free Audit","heading":"No Pitch. No Obligation. Real Analysis."},"block_type":"cta"}]'::jsonb,
  'emerald',
  '{"cta":{"href":"#audit","label":"INITIATE_HANDSHAKE"},"portfolio":[{"href":"/#hook","name":"The Problem"},{"href":"/#solution","name":"Architecture"},{"href":"/blog","name":"Blog & Knowledge Base"},{"href":"/guide/how-i-build","name":"How I Build"},{"href":"/search","name":"Search"}],"custom_apps":[{"href":"/services/custom-apps/python-api","name":"Python & FastAPI"},{"href":"/services/custom-apps/frontend","name":"Astro & React"},{"href":"/services/custom-apps/full-stack","name":"Full-Stack"},{"href":"/services/custom-apps/database","name":"PostgreSQL"},{"href":"/services/custom-apps/google-apis","name":"Google APIs"},{"href":"/services/custom-apps/wordpress","name":"WordPress"},{"href":"/services/custom-apps/calculators","name":"Calculators"},{"href":"/services/custom-apps/3d-visual","name":"3D & Visual"}],"growth_tools":[{"href":"https://jumpstartscaling.com","name":"Jumpstart Scaling"},{"href":"https://jumpstartscaling.com/services/growth-retainer","name":"Growth Retainer"},{"href":"https://jumpstartscaling.com/services/crm-transformation","name":"CRM Build"}]}'::jsonb,
  '{"tagline":"The Unicorn Developer.","copyright":"Chris Amaya"}'::jsonb
)
ON CONFLICT (slug) DO UPDATE SET
  title = EXCLUDED.title, blocks = EXCLUDED.blocks,
  palette = EXCLUDED.palette, nav = EXCLUDED.nav, footer = EXCLUDED.footer;

INSERT INTO caw_content (slug, title, blocks, palette, nav, footer)
VALUES (
  'blog',
  'Blog & Knowledge Base | Chris Amaya — Architecture, AI & Growth Systems',
  '[{"data":{"badge":"BLOG & KNOWLEDGE BASE","subhead":"Deep technical content on building sovereign infrastructure, private AI agents, PostgreSQL at scale, and full-stack systems design.","cta_href":"#topics","headline":"Architecture.<br class=\"hidden md:block\"/>AI Systems.<br class=\"hidden md:block\"/><span class=\"text-neon\">Growth Engineering.</span>","cta_label":"< EXPLORE_KNOWLEDGE />"},"block_type":"hero"},{"data":{"cards":[{"body":"Self-hosted alternatives to SaaS, Coolify deployment guides, n8n automation patterns, PostgreSQL schema design, and Docker production setups.","title":"< INFRASTRUCTURE />","border_color":"neon-blue"},{"body":"Private LLM deployment, RAG pipelines with pgvector, LangChain vs bare API patterns, and AI agents that run on your own hardware.","title":"< AI_SYSTEMS />","border_color":"neon-green"},{"body":"Server-side conversion tracking, CAPI setup, attribution modeling, CAC/LTV calculators, and funnel analytics that survive iOS14.","title":"< GROWTH_ENGINEERING />","border_color":"neon-pink"}],"title":"What I Write About","eyebrow":"// CONTENT_PILLARS"},"block_type":"solution_cards"},{"data":{"title":"Topic Index","bullets":[{"icon":"🏗️","text":"Why self-hosted beats SaaS past $1M revenue. Coolify, n8n, Supabase, and the stack for infrastructure independence.","title":"Sovereign Infrastructure"},{"icon":"🤖","text":"Running Llama, Mistral, and custom fine-tunes on your own VPS. No OpenAI data risk. Full control.","title":"Private AI Agents"},{"icon":"🐘","text":"JSONB vs relational, pgvector for semantic search, Row-Level Security for multi-tenancy, and asyncpg patterns.","title":"PostgreSQL Deep Dives"},{"icon":"📡","text":"Facebook CAPI, Google Enhanced Conversions, and TikTok Events API. Attribution without cookies or pixels.","title":"Server-Side Tracking"},{"icon":"⚡","text":"Async architecture, dependency injection, Pydantic v2, background tasks, and deployment on Coolify.","title":"FastAPI Patterns"},{"icon":"🌐","text":"SSR with Astro, React islands, Tailwind design systems, and building Lighthouse 100 marketing sites.","title":"Astro & Frontend"},{"icon":"🧮","text":"ROAS, CAC, LTV, cohort analysis. How I build interactive financial tools that capture leads and educate buyers.","title":"Calculator Architecture"},{"icon":"🔐","text":"SSH hardening, Docker secrets, PostgreSQL RLS, and zero-trust architecture for agencies handling client data.","title":"Security & DevOps"}]},"block_type":"icon_bullets"},{"data":{"body":"<p>The most common question I get after a strategy call: <em>\"What would you actually build for us?\"</em> The answer is almost always the same stack, adapted to the problem.</p><h3 class=\"text-white font-bold mt-6 mb-2\">The Core Stack</h3><p><strong class=\"text-white\">Backend:</strong> Python 3.12 + FastAPI + asyncpg + PostgreSQL 16. This handles everything from lead capture to AI agent orchestration to billing webhooks. One language, one database, full async.</p><p class=\"mt-3\"><strong class=\"text-white\">Automation:</strong> Self-hosted n8n on a $10/mo VPS (or shared with the main server). Replaces Zapier entirely. Handles CRM syncs, email sequences, Slack notifications, and webhook relay without per-task fees.</p><p class=\"mt-3\"><strong class=\"text-white\">Frontend:</strong> Astro SSR for marketing pages, React for dashboards and interactive tools. Tailwind for design system. Zero client-side JavaScript unless needed.</p><p class=\"mt-3\"><strong class=\"text-white\">Infra:</strong> Coolify on a Hetzner or Digital Ocean VPS. Git-push deploys. Auto SSL. Docker Compose per service. Total cost: $50–$200/mo depending on scale, vs. $3,000–$5,000/mo in SaaS subscriptions.</p><p class=\"mt-3\"><strong class=\"text-white\">AI:</strong> Ollama + pgvector for private LLM operations. OpenAI API only for non-sensitive tasks. Fine-tuned Llama for client-specific workflows.</p>","title":"Featured: The Sovereign Stack Guide"},"block_type":"value_prop"},{"data":{"body":"<p>Every post on this blog comes from a system I have actually deployed in production. No tutorial repos. No \"example\" codebases. If I write about a PostgreSQL optimization, it is because I ran EXPLAIN ANALYZE on a 50M-row table and found the winning index.</p><p class=\"mt-4\">I have built systems for media agencies, solar installation companies, law firms, e-commerce brands, and SaaS startups. The patterns repeat. The mistakes repeat. The solutions I write about are the ones that closed the gap between \"it works in dev\" and \"it works at scale.\"</p>","stats":[{"label":"Systems Referenced","value":"50+"},{"label":"Production Experience","value":"8yr"},{"label":"Revenue on These Stacks","value":"$10M+"}],"title":"Built From Real Projects, Not Tutorials"},"block_type":"authority"},{"data":{"href":"/contact","text":"Reading about architecture is useful. Having it built for you is better.","label":"Book a Strategy Session","heading":"Want This Applied to Your Stack?"},"block_type":"cta"}]'::jsonb,
  'emerald',
  '{"cta":{"href":"#audit","label":"INITIATE_HANDSHAKE"},"portfolio":[{"href":"/#hook","name":"The Problem"},{"href":"/#solution","name":"Architecture"},{"href":"/blog","name":"Blog & Knowledge Base"},{"href":"/guide/how-i-build","name":"How I Build"},{"href":"/search","name":"Search"}],"custom_apps":[{"href":"/services/custom-apps/python-api","name":"Python & FastAPI"},{"href":"/services/custom-apps/frontend","name":"Astro & React"},{"href":"/services/custom-apps/full-stack","name":"Full-Stack"},{"href":"/services/custom-apps/database","name":"PostgreSQL"},{"href":"/services/custom-apps/google-apis","name":"Google APIs"},{"href":"/services/custom-apps/wordpress","name":"WordPress"},{"href":"/services/custom-apps/calculators","name":"Calculators"},{"href":"/services/custom-apps/3d-visual","name":"3D & Visual"}],"growth_tools":[{"href":"https://jumpstartscaling.com","name":"Jumpstart Scaling"},{"href":"https://jumpstartscaling.com/services/growth-retainer","name":"Growth Retainer"},{"href":"https://jumpstartscaling.com/services/crm-transformation","name":"CRM Build"}]}'::jsonb,
  '{"tagline":"The Unicorn Developer.","copyright":"Chris Amaya"}'::jsonb
)
ON CONFLICT (slug) DO UPDATE SET
  title = EXCLUDED.title, blocks = EXCLUDED.blocks,
  palette = EXCLUDED.palette, nav = EXCLUDED.nav, footer = EXCLUDED.footer;

INSERT INTO caw_content (slug, title, blocks, palette, nav, footer)
VALUES (
  'contact',
  'Contact | Chris Amaya — Book a Technical Strategy Session',
  '[{"data":{"badge":"CONTACT // OPEN CHANNEL","subhead":"No pitch decks. No sales calls. One conversation about your stack, your bottlenecks, and whether there is a fit.","cta_href":"#audit","headline":"Book a<br class=\"hidden md:block\"/>Technical<br class=\"hidden md:block\"/><span class=\"text-neon\">Strategy Session.</span>","cta_label":"< OPEN_CHANNEL />","warning_text":"// Minimum engagement: $10k. Response time: <24hr."},"block_type":"hero"},{"data":{"cards":[{"body":"45-minute deep-dive into your current stack. I map the bottlenecks, Zapier costs, and single points of failure — live on the call.","title":"< 01. STRATEGY_SESSION />","border_color":"neon-blue"},{"body":"Within 48 hours you get a written system design doc: tech stack, timeline, and cost estimate. No obligation.","title":"< 02. ARCHITECTURE_PLAN />","border_color":"neon-green"},{"body":"14-day sprints. Each sprint delivers a production deployment — not a staging environment, not a prototype.","title":"< 03. BUILD />","border_color":"neon-pink"}],"title":"Three Steps to Sovereign Infrastructure","eyebrow":"// HOW_IT_WORKS"},"block_type":"solution_cards"},{"data":{"title":"What Clients Say Before They Book","bullets":[{"icon":"😤","text":"Happening to 80% of agencies past $500k. Self-hosted n8n on your VPS eliminates per-task fees and webhook timeouts.","title":"\"Zapier keeps breaking our lead flow.\""},{"icon":"😰","text":"Server-side CAPI + attribution dashboard. Built in one sprint. Tracks every source to every close.","title":"\"We can''t see where our leads come from.\""},{"icon":"🤯","text":"Architecture review first. Then 14-day delivery cycles. Not agile theater — actual deployed code.","title":"\"Our dev team takes 3 weeks to ship anything.\""},{"icon":"💸","text":"Self-hosted alternatives for CRM, automation, analytics. Your servers. Your data. No per-seat fees.","title":"\"SaaS bills are eating our margins.\""},{"icon":"🔒","text":"Private LLMs on your own infra. Llama, Mistral, or fine-tuned models — no OpenAI data sharing.","title":"\"We need AI but can''t risk data leaks.\""},{"icon":"🚀","text":"The systems that got you to $1M will not get you to $5M. Architect first, scale second.","title":"\"We need to scale from $1M to $5M.\""}]},"block_type":"icon_bullets"},{"data":{"title":"Book a Technical Strategy Session","subhead":"Fill out the form. I will respond within 24 hours with a calendar link.","form_title":"INITIATE_HANDSHAKE_PROTOCOL","submit_source":"ChrisAmayaWork-Contact"},"block_type":"audit_form"},{"data":{"body":"<h3 class=\"text-white font-bold mt-6 mb-2\">What is the minimum engagement size?</h3><p>$10,000 minimum. Most projects run $15k–$50k depending on scope. I do not take $500 \"fix my WordPress\" jobs.</p><h3 class=\"text-white font-bold mt-6 mb-2\">How fast can you start?</h3><p>Typically within 1–2 weeks of agreement. I carry two active clients at a time so availability is limited.</p><h3 class=\"text-white font-bold mt-6 mb-2\">Do you do ongoing retainers?</h3><p>Yes. After the initial build I offer a monthly architecture retainer for teams that want continued system evolution without hiring a CTO.</p><h3 class=\"text-white font-bold mt-6 mb-2\">What tech stack do you use?</h3><p>Python/FastAPI + PostgreSQL on the backend. Astro/React/Vite on the frontend. n8n for automation. Self-hosted infra via Coolify or Docker Compose. Google Cloud when needed for Maps/Solar APIs.</p><h3 class=\"text-white font-bold mt-6 mb-2\">Will you work with an existing team?</h3><p>Yes. I frequently audit and extend existing codebases. I am comfortable being the lead architect while your junior devs handle execution.</p>","title":"Frequently Asked Questions"},"block_type":"value_prop"},{"data":{"href":"#audit","text":"If your stack needs a real architect — not another freelancer — let''s talk.","label":"Start the Conversation","heading":"Two Client Slots Open for Q1."},"block_type":"cta"}]'::jsonb,
  'emerald',
  '{"cta":{"href":"#audit","label":"INITIATE_HANDSHAKE"},"portfolio":[{"href":"/#hook","name":"The Problem"},{"href":"/#solution","name":"Architecture"},{"href":"/blog","name":"Blog & Knowledge Base"},{"href":"/guide/how-i-build","name":"How I Build"},{"href":"/search","name":"Search"}],"custom_apps":[{"href":"/services/custom-apps/python-api","name":"Python & FastAPI"},{"href":"/services/custom-apps/frontend","name":"Astro & React"},{"href":"/services/custom-apps/full-stack","name":"Full-Stack"},{"href":"/services/custom-apps/database","name":"PostgreSQL"},{"href":"/services/custom-apps/google-apis","name":"Google APIs"},{"href":"/services/custom-apps/wordpress","name":"WordPress"},{"href":"/services/custom-apps/calculators","name":"Calculators"},{"href":"/services/custom-apps/3d-visual","name":"3D & Visual"}],"growth_tools":[{"href":"https://jumpstartscaling.com","name":"Jumpstart Scaling"},{"href":"https://jumpstartscaling.com/services/growth-retainer","name":"Growth Retainer"},{"href":"https://jumpstartscaling.com/services/crm-transformation","name":"CRM Build"}]}'::jsonb,
  '{"tagline":"The Unicorn Developer.","copyright":"Chris Amaya"}'::jsonb
)
ON CONFLICT (slug) DO UPDATE SET
  title = EXCLUDED.title, blocks = EXCLUDED.blocks,
  palette = EXCLUDED.palette, nav = EXCLUDED.nav, footer = EXCLUDED.footer;

INSERT INTO caw_content (slug, title, blocks, palette, nav, footer)
VALUES (
  'guide/how-i-build',
  'How I Build | Chris Amaya — Architecture Methodology',
  '[{"data":{"badge":"METHODOLOGY // HOW I BUILD","subhead":"A repeatable architecture methodology refined across 50+ systems. No sprints that slip. No deploys that break. No handoff chaos.","cta_href":"#process","headline":"From Discovery<br class=\"hidden md:block\"/>to<br class=\"hidden md:block\"/><span class=\"text-neon\">Production in 14 Days.</span>","cta_label":"< READ_THE_PROCESS />"},"block_type":"hero"},{"data":{"cards":[{"body":"Week 0 (before any code): I audit your current stack, map all integrations, identify single points of failure, and define the MVP scope in a written architecture document.","title":"< PHASE_1: DISCOVERY />","border_color":"neon-blue"},{"body":"Day 1–3: Schema design, API contract definition, infrastructure choices, and repository setup. Every decision is documented before implementation begins.","title":"< PHASE_2: DESIGN />","border_color":"neon-green"},{"body":"Day 4–14: Implementation in fast cycles. Each cycle ends in a production deployment — not staging, not a demo. Real URLs, real data, real results.","title":"< PHASE_3: DEPLOY />","border_color":"neon-pink"}],"title":"Discovery → Design → Deploy","eyebrow":"// THE_THREE_PHASES"},"block_type":"solution_cards"},{"data":{"body":"<p>The single biggest mistake teams make is writing code before the architecture is decided. This creates technical debt that compounds over every sprint. Refactoring a live system costs 5–10x more than designing it correctly from the start.</p><p class=\"mt-4\">Every engagement I take begins with a 48-hour architecture sprint: no code, just design. I produce a written document covering the database schema, API contract, infrastructure diagram, and deployment strategy. Only after that document is approved does line one of code get written.</p><h3 class=\"text-white font-bold mt-6 mb-2\">The Technology Decisions I Make (And Why)</h3><p><strong class=\"text-white\">Python FastAPI over Node Express</strong> — Async by default, Pydantic validation, OpenAPI docs generated automatically. Superior for data-heavy backends.</p><p class=\"mt-3\"><strong class=\"text-white\">PostgreSQL over MongoDB</strong> — JSONB columns give you document flexibility with relational integrity. I use pg-vector for AI search, RLS for multi-tenancy, and logical replication for scaling.</p><p class=\"mt-3\"><strong class=\"text-white\">Astro over Next.js for marketing</strong> — Zero JavaScript by default. HTML ships to the browser. React islands only where needed. Result: Lighthouse scores in the 95–100 range.</p><p class=\"mt-3\"><strong class=\"text-white\">Self-hosted n8n over Zapier</strong> — One-time server cost vs. per-task fees that scale with your success. You own the automation engine.</p><p class=\"mt-3\"><strong class=\"text-white\">Coolify over AWS/Heroku</strong> — Self-hosted PaaS on a $50/mo VPS. Git push deploys, SSL, Docker, database — no cloud provider lock-in.</p>","title":"The Architecture-First Principle"},"block_type":"value_prop"},{"data":{"body":"These are the failure patterns I see in every agency codebase I audit. Each one is preventable with proper architecture.","title":"What Most Dev Projects Do Wrong","bullets":["❌ No schema before code: database changes break the API weekly","❌ Zapier as business logic: webhook reliability is 97% — that 3% loses leads","❌ No server-side tracking: iOS14 killed 40–60% of pixel attribution","❌ Monolithic deploys: one bug in one feature takes down the whole site","❌ No local dev parity: \"works on my machine\" delays every sprint"],"eyebrow":"// ANTI_PATTERNS_I_ELIMINATE","status_text":"_ BUILD_VELOCITY: NOMINAL","terminal_logs":[{"msg":"[OK] Architecture doc approved. Schema committed. API contracts defined.","time":"SPRINT_01"},{"msg":"[DEPLOY] Database migrations applied. Zero downtime.","time":"SPRINT_01"},{"msg":"[DEPLOY] API live at api.yourdomain.com — health check passing.","time":"SPRINT_01"},{"msg":"[OK] Frontend connected. First real user data flowing.","time":"SPRINT_02"}]},"block_type":"terminal_problem"},{"data":{"title":"The Stack I Use and Why","bullets":[{"icon":"🐍","text":"Async Python for high-throughput APIs. asyncpg is 3x faster than SQLAlchemy for read-heavy workloads.","title":"FastAPI + asyncpg"},{"icon":"🐘","text":"One database for relational data, JSONB documents, and vector AI search. No need for Redis, MongoDB, and Pinecone separately.","title":"PostgreSQL + pgvector"},{"icon":"🚀","text":"HTML-first rendering. React/Vue islands for interactivity. The fastest possible time-to-first-byte for marketing pages.","title":"Astro SSR"},{"icon":"⚙️","text":"Visual workflow automation on your own VPS. No per-task fees. Runs 24/7 without Zapier timeouts.","title":"n8n Self-Hosted"},{"icon":"🐳","text":"PaaS on your own hardware. Git push to deploy. Zero cloud lock-in. Total infrastructure sovereignty.","title":"Coolify + Docker"},{"icon":"📡","text":"Facebook, Google, and TikTok Conversion APIs via your backend. Attribution that survives iOS14, ad blockers, and cookie death.","title":"Server-Side CAPI"}]},"block_type":"icon_bullets"},{"data":{"title":"Want This Process Applied to Your Project?","subhead":"Let''s run a discovery session on your stack.","form_title":"START_DISCOVERY_PROTOCOL","submit_source":"ChrisAmayaWork-Guide"},"block_type":"audit_form"},{"data":{"href":"#audit","text":"Two Q1 slots open. The methodology works. The question is whether your project qualifies.","label":"Apply for a Project Slot","heading":"Architecture First. Speed Follows."},"block_type":"cta"}]'::jsonb,
  'emerald',
  '{"cta":{"href":"#audit","label":"INITIATE_HANDSHAKE"},"portfolio":[{"href":"/#hook","name":"The Problem"},{"href":"/#solution","name":"Architecture"},{"href":"/blog","name":"Blog & Knowledge Base"},{"href":"/guide/how-i-build","name":"How I Build"},{"href":"/search","name":"Search"}],"custom_apps":[{"href":"/services/custom-apps/python-api","name":"Python & FastAPI"},{"href":"/services/custom-apps/frontend","name":"Astro & React"},{"href":"/services/custom-apps/full-stack","name":"Full-Stack"},{"href":"/services/custom-apps/database","name":"PostgreSQL"},{"href":"/services/custom-apps/google-apis","name":"Google APIs"},{"href":"/services/custom-apps/wordpress","name":"WordPress"},{"href":"/services/custom-apps/calculators","name":"Calculators"},{"href":"/services/custom-apps/3d-visual","name":"3D & Visual"}],"growth_tools":[{"href":"https://jumpstartscaling.com","name":"Jumpstart Scaling"},{"href":"https://jumpstartscaling.com/services/growth-retainer","name":"Growth Retainer"},{"href":"https://jumpstartscaling.com/services/crm-transformation","name":"CRM Build"}]}'::jsonb,
  '{"tagline":"The Unicorn Developer.","copyright":"Chris Amaya"}'::jsonb
)
