INSERT INTO caw_content (slug, title, blocks, palette, nav, footer)
VALUES (
  'privacy',
  'Privacy Policy | Chris Amaya',
  '[{"data":{"badge":"LEGAL // PRIVACY POLICY","subhead":"Effective date: January 1, 2025. I take data seriously — especially yours.","cta_href":"/contact","headline":"Privacy<br class=\"hidden md:block\"/><span class=\"text-neon\">Policy.</span>","cta_label":"Contact"},"block_type":"hero"},{"data":{"body":"<p>When you submit a contact form on this site I collect: your name, email address, company revenue range, budget range, and problem description. This data is stored in a private PostgreSQL database hosted on infrastructure I control.</p><h3 class=\"text-white font-bold mt-6 mb-2\">What I Do Not Do</h3><p>I do not sell your data. I do not share it with marketing platforms. I do not run retargeting pixels on form submissions. I do not use third-party CRM tools that sync your data to Salesforce, HubSpot, or any external SaaS without your explicit consent.</p><h3 class=\"text-white font-bold mt-6 mb-2\">How I Use Your Data</h3><p>Form submissions are used solely to respond to your inquiry and, if you become a client, to manage our engagement. I may email you with relevant architectural insights if you opt in, but I do not have an automated marketing sequence.</p><h3 class=\"text-white font-bold mt-6 mb-2\">Cookies & Analytics</h3><p>This site uses minimal analytics. I do not run Google Analytics, Facebook Pixel, or TikTok Pixel on chrisamaya.work. Any tracking is server-side and privacy-preserving.</p><h3 class=\"text-white font-bold mt-6 mb-2\">Your Rights</h3><p>You may request deletion of your data at any time by contacting me through the <a href=\"/contact\" class=\"text-neon\">contact page</a>. I will delete all records within 72 hours of a verified request.</p><h3 class=\"text-white font-bold mt-6 mb-2\">Data Security</h3><p>All data is stored on private servers with encrypted connections (TLS). Database access is restricted to authenticated systems. No client data is stored in third-party cloud platforms without written agreement.</p><h3 class=\"text-white font-bold mt-6 mb-2\">Third Parties</h3><p>This site may link to third-party sites (Jumpstart Scaling, GitHub, LinkedIn). I am not responsible for their privacy practices.</p><h3 class=\"text-white font-bold mt-6 mb-2\">Contact</h3><p>Privacy questions: use the <a href=\"/contact\" class=\"text-neon\">contact page</a>.</p>","title":"What Data I Collect"},"block_type":"value_prop"},{"data":{"href":"/about","text":"I build the same privacy-first infrastructure for clients. Sovereign by default.","label":"Learn About My Approach","heading":"Your Data Stays Yours."},"block_type":"cta"}]'::jsonb,
  'emerald',
  '{"cta":{"href":"#audit","label":"INITIATE_HANDSHAKE"},"portfolio":[{"href":"/#hook","name":"The Problem"},{"href":"/#solution","name":"Architecture"},{"href":"/blog","name":"Blog & Knowledge Base"},{"href":"/guide/how-i-build","name":"How I Build"},{"href":"/search","name":"Search"}],"custom_apps":[{"href":"/services/custom-apps/python-api","name":"Python & FastAPI"},{"href":"/services/custom-apps/frontend","name":"Astro & React"},{"href":"/services/custom-apps/full-stack","name":"Full-Stack"},{"href":"/services/custom-apps/database","name":"PostgreSQL"},{"href":"/services/custom-apps/google-apis","name":"Google APIs"},{"href":"/services/custom-apps/wordpress","name":"WordPress"},{"href":"/services/custom-apps/calculators","name":"Calculators"},{"href":"/services/custom-apps/3d-visual","name":"3D & Visual"}],"growth_tools":[{"href":"https://jumpstartscaling.com","name":"Jumpstart Scaling"},{"href":"https://jumpstartscaling.com/services/growth-retainer","name":"Growth Retainer"},{"href":"https://jumpstartscaling.com/services/crm-transformation","name":"CRM Build"}]}'::jsonb,
  '{"tagline":"The Unicorn Developer.","copyright":"Chris Amaya"}'::jsonb
)
