INSERT INTO caw_content (slug, title, blocks, palette, nav, footer)
VALUES (
  'resources/calculators',
  'Free Growth Calculators | Chris Amaya — ROAS, CAC, LTV & More',
  '[{"data":{"badge":"FREE TOOLS // CALCULATORS","subhead":"ROAS, CAC, LTV, cohort analysis, email ROI, and funnel forecasters. Built with the same React stack I use for client tools.","cta_href":"https://jumpstartscaling.com/resources/calculators","headline":"Growth<br class=\"hidden md:block\"/>Engineering<br class=\"hidden md:block\"/><span class=\"text-neon\">Calculators.</span>","cta_label":"< ACCESS_TOOLS />"},"block_type":"hero"},{"data":{"cards":[{"body":"Enter ad spend and revenue by channel. Instantly see true ROAS, blended ROAS, and which channels are underwater.","title":"< ROAS_CALCULATOR />","border_color":"neon-blue"},{"body":"Lifetime value vs. customer acquisition cost. Payback period, break-even point, and channel efficiency scoring.","title":"< LTV_CAC_MODEL />","border_color":"neon-green"},{"body":"Start with impressions, model through to close. See exactly where leads are dropping off and what fixing each stage is worth.","title":"< FUNNEL_FORECASTER />","border_color":"neon-pink"}],"title":"Interactive Growth Calculators","eyebrow":"// AVAILABLE_TOOLS"},"block_type":"solution_cards"},{"data":{"title":"Full Calculator Suite","bullets":[{"icon":"📊","text":"Return on ad spend by channel. Identify winners and kill losers with actual math.","title":"ROAS Calculator"},{"icon":"👤","text":"Customer acquisition cost vs. lifetime value. The ratio that determines whether your business is a profit machine or a treadmill.","title":"CAC / LTV Model"},{"icon":"📧","text":"Revenue per subscriber, campaign ROI, and list health scoring.","title":"Email ROI Calculator"},{"icon":"🔄","text":"Retention, churn, and revenue cohorts. See how customer value changes over time.","title":"Cohort Analysis Tool"},{"icon":"📉","text":"What would happen if you improved each stage by 10%? Model the compounding impact.","title":"Funnel Forecaster"},{"icon":"🧮","text":"Projected customer lifetime value at different retention rates. Price your acquisition budget correctly.","title":"CLV Retention Model"}]},"block_type":"icon_bullets"},{"data":{"section_title":"Access All Calculators at Jumpstart Scaling"},"block_type":"calculator"},{"data":{"body":"<p>Every client engagement starts with the same question: \"Do you actually know your numbers?\" Most agencies have revenue. Few have data. These calculators close the gap between gut feel and engineered growth.</p><p class=\"mt-4\">They are built with the same React stack I use for client-facing calculator products. Interactive, embeddable, and accurate. The math is not simplified for the sake of UX — it reflects how real media buying works.</p><p class=\"mt-4\">If you need a custom calculator for your product — ROAS tool for a marketing agency, equity vesting calculator for a SaaS, solar ROI tool for a roofing company — <a href=\"/contact\" class=\"text-neon\">let''s build it</a>. These are a $3,000–$8,000 project typically and generate leads for months.</p>","title":"Why I Built These Tools"},"block_type":"value_prop"},{"data":{"href":"/contact","text":"Lead-magnet calculators built in React. Embed on any site. Start capturing leads with real tools.","label":"Scope a Calculator Project","heading":"Need a Custom Calculator for Your Product?"},"block_type":"cta"}]'::jsonb,
  'emerald',
  '{"cta":{"href":"#audit","label":"INITIATE_HANDSHAKE"},"portfolio":[{"href":"/#hook","name":"The Problem"},{"href":"/#solution","name":"Architecture"},{"href":"/blog","name":"Blog & Knowledge Base"},{"href":"/guide/how-i-build","name":"How I Build"},{"href":"/search","name":"Search"}],"custom_apps":[{"href":"/services/custom-apps/python-api","name":"Python & FastAPI"},{"href":"/services/custom-apps/frontend","name":"Astro & React"},{"href":"/services/custom-apps/full-stack","name":"Full-Stack"},{"href":"/services/custom-apps/database","name":"PostgreSQL"},{"href":"/services/custom-apps/google-apis","name":"Google APIs"},{"href":"/services/custom-apps/wordpress","name":"WordPress"},{"href":"/services/custom-apps/calculators","name":"Calculators"},{"href":"/services/custom-apps/3d-visual","name":"3D & Visual"}],"growth_tools":[{"href":"https://jumpstartscaling.com","name":"Jumpstart Scaling"},{"href":"https://jumpstartscaling.com/services/growth-retainer","name":"Growth Retainer"},{"href":"https://jumpstartscaling.com/services/crm-transformation","name":"CRM Build"}]}'::jsonb,
  '{"tagline":"The Unicorn Developer.","copyright":"Chris Amaya"}'::jsonb
)
