INSERT INTO caw_content (slug, title, blocks, palette, nav, footer)
VALUES (
  'services',
  'Services | Chris Amaya — Custom Software Architecture',
  '[{"data":{"badge":"SERVICES // WHAT I BUILD","subhead":"Backend APIs, private AI, headless CMS, Google integrations, 3D visuals, custom calculators. One architect. Zero agency markup.","cta_href":"#services-grid","headline":"Sovereign Systems<br class=\"hidden md:block\"/>For<br class=\"hidden md:block\"/><span class=\"text-neon\">Scaling Agencies.</span>","cta_label":"< SEE_ALL_SERVICES />"},"block_type":"hero"},{"data":{"cards":[{"body":"Python & FastAPI custom APIs, private LLM agents, PostgreSQL schema design, asyncpg integrations, and self-hosted automation engines.","title":"< BACKEND / AI />","border_color":"neon-blue"},{"body":"Astro SSR, React dashboards, Vite apps, headless WordPress, and full-stack DB-driven sites like chrisamaya.work.","title":"< FRONTEND / FULL-STACK />","border_color":"neon-green"},{"body":"Google Solar/Maps/Roofing API integrations, ROAS calculators, lead-capture tools, server-side CAPI attribution.","title":"< GROWTH / TOOLS />","border_color":"neon-pink"}],"title":"Engineering Services","eyebrow":"// CORE_SERVICES"},"block_type":"solution_cards"},{"data":{"title":"Full Service Menu","bullets":[{"icon":"🐍","text":"Async REST and WebSocket backends. asyncpg + PostgreSQL. Webhook processors, CRM sync engines, AI orchestration layers.","title":"Python & FastAPI"},{"icon":"⚛️","text":"Marketing sites, client portals, dashboards. SSR-first. Tailwind. Framer animations. Lighthouse 95+.","title":"Astro & React Apps"},{"icon":"🏗️","text":"DB-driven multi-tenant SaaS. Auth, roles, billing, API — the whole stack from schema to deploy button.","title":"Full-Stack Architecture"},{"icon":"🗄️","text":"Schema design, indexes, migrations, RLS, pgvector for AI search. Production-grade from day one.","title":"PostgreSQL Design"},{"icon":"🗺️","text":"Solar potential, roofing, Maps, Places, Geocoding, Directions. Custom apps on top of the full Google geo stack.","title":"Google APIs"},{"icon":"📰","text":"REST API, GraphQL (WPGraphQL), custom post types, ACF, WooCommerce. Astro or React on the frontend.","title":"Headless WordPress"},{"icon":"🧮","text":"ROAS, CAC, LTV, funnel forecasters. Lead-magnet interactive tools in React. Embeddable or standalone.","title":"Calculators & Tools"},{"icon":"🌐","text":"3D product visuals, Rive animations, Spline scenes. WebGL performance-optimized for marketing sites.","title":"Three.js, Rive & Spline"}]},"block_type":"icon_bullets"},{"data":{"body":"<p>An agency charges you for project management, account management, and handoff overhead. I charge you for architecture and code. Every dollar goes to the system, not the org chart.</p><p class=\"mt-4\">I have worked as a solo architect on systems that would typically require a 4–6 person team. The secret is system design: when the architecture is right, implementation is fast. When it is wrong, no amount of headcount saves you.</p>","stats":[{"label":"Average Sprint","value":"14 days"},{"label":"Agency Markup","value":"$0"},{"label":"Code Ownership Yours","value":"100%"}],"title":"Why One Architect Beats an Agency"},"block_type":"authority"},{"data":{"title":"Scope Your Project","subhead":"Tell me what you''re building. I''ll tell you what stack it needs.","form_title":"SCOPE_PROJECT_PROTOCOL","submit_source":"ChrisAmayaWork-Services"},"block_type":"audit_form"},{"data":{"href":"#audit","text":"Two Q1 slots available. Projects start within two weeks of agreement.","label":"Start a Conversation","heading":"Pick Your Stack. Secure Your Slot."},"block_type":"cta"}]'::jsonb,
  'emerald',
  '{"cta":{"href":"#audit","label":"INITIATE_HANDSHAKE"},"portfolio":[{"href":"/#hook","name":"The Problem"},{"href":"/#solution","name":"Architecture"},{"href":"/blog","name":"Blog & Knowledge Base"},{"href":"/guide/how-i-build","name":"How I Build"},{"href":"/search","name":"Search"}],"custom_apps":[{"href":"/services/custom-apps/python-api","name":"Python & FastAPI"},{"href":"/services/custom-apps/frontend","name":"Astro & React"},{"href":"/services/custom-apps/full-stack","name":"Full-Stack"},{"href":"/services/custom-apps/database","name":"PostgreSQL"},{"href":"/services/custom-apps/google-apis","name":"Google APIs"},{"href":"/services/custom-apps/wordpress","name":"WordPress"},{"href":"/services/custom-apps/calculators","name":"Calculators"},{"href":"/services/custom-apps/3d-visual","name":"3D & Visual"}],"growth_tools":[{"href":"https://jumpstartscaling.com","name":"Jumpstart Scaling"},{"href":"https://jumpstartscaling.com/services/growth-retainer","name":"Growth Retainer"},{"href":"https://jumpstartscaling.com/services/crm-transformation","name":"CRM Build"}]}'::jsonb,
