INSERT INTO caw_content (slug, title, blocks, palette, nav, footer)
VALUES (
  'services/custom-apps/3d-visual',
  'Three.js, Rive & 3D Visual | Interactive Web Experiences | Chris Amaya',
  '[{"data":{"badge":"3D & VISUAL // THREE.JS & RIVE","subhead":"Three.js product visualizers, Rive interactive animations, Spline scenes embedded in marketing pages. Motion and 3D that serve conversion goals — not just look impressive.","cta_href":"#audit","headline":"3D Experiences<br class=\"hidden md:block\"/>That<br class=\"hidden md:block\"/><span class=\"text-neon\">Convert.</span>","cta_label":"< DISCUSS_YOUR_VISION />"},"block_type":"hero"},{"data":{"cards":[{"body":"3D product configurators, data visualizations, globe animations, and interactive scenes. WebGL performance-optimized to run smoothly on mid-range devices.","title":"< THREE.JS />","border_color":"neon-blue"},{"body":"Interactive character animations, state machines for UI animations, and motion graphics that respond to user input. Exported as compact binary, runs at 60fps.","title":"< RIVE />","border_color":"neon-green"},{"body":"Design-to-3D pipeline using Spline. Drag-and-drop 3D design exported directly to your React or Astro page. Fastest path from concept to embedded 3D.","title":"< SPLINE />","border_color":"neon-pink"}],"title":"Three Layers of Visual Impact","eyebrow":"// VISUAL_STACK"},"block_type":"solution_cards"},{"data":{"title":"3D & Motion Use Cases","bullets":[{"icon":"📦","text":"360° product view with material and color variants. Click to change options. Three.js handles the 3D, React handles the UI.","title":"Product Configurator"},{"icon":"🌐","text":"Animated 3D globe showing service locations, global reach, or data distribution. Classic for enterprise and SaaS marketing.","title":"Data Globe"},{"icon":"🎭","text":"Rive animation as the hero visual. Responds to scroll, hover, or cursor. Feels alive. Smaller file than a video, interactive unlike an image.","title":"Hero Section Animation"},{"icon":"🏗️","text":"Animated system diagram showing how your product works. Three.js nodes and edges. Infinitely better than a static PowerPoint slide.","title":"Architecture Diagram"},{"icon":"🎪","text":"Three.js camera moves as the user scrolls. Product reveals, feature callouts, and transitions driven by scroll position.","title":"Scroll Storytelling"},{"icon":"📊","text":"Bar charts, scatter plots, and network graphs in 3D. More memorable and shareable than flat charts for annual reports and product launches.","title":"3D Data Visualization"}]},"block_type":"icon_bullets"},{"data":{"body":"<p>The single biggest failure mode in 3D web work is shipping a beautiful experience that runs at 15fps on anything other than a top-of-the-line MacBook Pro. I optimize every Three.js scene for mobile-first performance.</p><p class=\"mt-4\"><strong class=\"text-white\">Techniques I use:</strong></p><p class=\"mt-2\">• Level of Detail (LOD) — lower polygon models at distance<br/>• Instance meshes for repeated geometry (1,000 particles = 1 draw call)<br/>• DRACO compression for geometry files (often 80% size reduction)<br/>• KTX2 textures for GPU-compressed assets<br/>• RequestAnimationFrame optimization — pause when tab is not visible<br/>• Progressive loading — scene loads in stages, not all at once</p><p class=\"mt-4\">The result is a Three.js scene that runs at 60fps on a 2019-era mid-range Android device — the real performance baseline for most audiences.</p>","title":"Performance is Not Optional"},"block_type":"value_prop"},{"data":{"body":"Most agencies selling 3D web work do not benchmark. Here is what I see in production audits.","title":"What \"3D Website\" Actually Means for Performance","bullets":["⚠ Uncompressed GLB file: 45MB — 30 seconds to load on mobile","⚠ No LOD — same polygon count at 10px and 1000px render size","⚠ Three.js renderer not disposed on component unmount — memory leak","⚠ All assets load synchronously — white screen for 8+ seconds"],"eyebrow":"// 3D_PERFORMANCE_REALITY","status_text":"_ 3D_OPTIMIZED: MOBILE_VIABLE","terminal_logs":[{"msg":"[PERF] Initial load: 45MB assets, 8.2s LCP, mobile score 22","time":"BEFORE"},{"msg":"[OPT] GLB compressed: 45MB → 3.1MB (DRACO + texture compression)","time":"DRACO"},{"msg":"[PERF] Load: 3.1MB, 1.4s LCP on 3G, mobile Lighthouse 78","time":"AFTER"}]},"block_type":"terminal_problem"},{"data":{"title":"Tell Me Your Visual Goal","subhead":"What do you want a visitor to feel when they land on your page? I''ll design the experience.","form_title":"VISUAL_SCOPE_PROTOCOL","submit_source":"ChrisAmayaWork-3DVisual"},"block_type":"audit_form"},{"data":{"href":"#audit","text":"Stunning at 60fps on mobile. Conversion-optimized. Not just impressive — effective.","label":"Discuss the Vision","heading":"3D That Performs on Every Device."},"block_type":"cta"}]'::jsonb,
  'emerald',
  '{"cta":{"href":"#audit","label":"INITIATE_HANDSHAKE"},"portfolio":[{"href":"/#hook","name":"The Problem"},{"href":"/#solution","name":"Architecture"},{"href":"/blog","name":"Blog & Knowledge Base"},{"href":"/guide/how-i-build","name":"How I Build"},{"href":"/search","name":"Search"}],"custom_apps":[{"href":"/services/custom-apps/python-api","name":"Python & FastAPI"},{"href":"/services/custom-apps/frontend","name":"Astro & React"},{"href":"/services/custom-apps/full-stack","name":"Full-Stack"},{"href":"/services/custom-apps/database","name":"PostgreSQL"},{"href":"/services/custom-apps/google-apis","name":"Google APIs"},{"href":"/services/custom-apps/wordpress","name":"WordPress"},{"href":"/services/custom-apps/calculators","name":"Calculators"},{"href":"/services/custom-apps/3d-visual","name":"3D & Visual"}],"growth_tools":[{"href":"https://jumpstartscaling.com","name":"Jumpstart Scaling"},{"href":"https://jumpstartscaling.com/services/growth-retainer","name":"Growth Retainer"},{"href":"https://jumpstartscaling.com/services/crm-transformation","name":"CRM Build"}]}'::jsonb,
  '{"tagline":"The Unicorn Developer.","copyright":"Chris Amaya"}'::jsonb
)
ON CONFLICT (slug) DO UPDATE SET
  title = EXCLUDED.title, blocks = EXCLUDED.blocks,
  palette = EXCLUDED.palette, nav = EXCLUDED.nav, footer = EXCLUDED.footer;

INSERT INTO caw_content (slug, title, blocks, palette, nav, footer)
VALUES (
  'services/custom-apps/calculators',
  'Custom React Calculators & Interactive Tools | Chris Amaya',
  '[{"data":{"badge":"TOOLS // REACT CALCULATORS","subhead":"ROAS, CAC, LTV, ROI, solar savings, mortgage, funnel forecasters. Custom React calculators that educate buyers, demonstrate value, and capture leads in the same interaction.","cta_href":"#audit","headline":"Interactive Tools<br class=\"hidden md:block\"/>That<br class=\"hidden md:block\"/><span class=\"text-neon\">Capture Leads.</span>","cta_label":"< BUILD_A_CALCULATOR />"},"block_type":"hero"},{"data":{"cards":[{"body":"ROAS, CAC, LTV, payback period, pricing calculators, gross margin models. For agencies, SaaS, and service businesses that sell on ROI.","title":"< FINANCIAL_TOOLS />","border_color":"neon-blue"},{"body":"Solar savings, roofing estimates, mortgage, legal fee estimators, SaaS pricing configurators. Input your industry''s variables, get a custom quote or projection.","title":"< INDUSTRY_SPECIFIC />","border_color":"neon-green"},{"body":"Media planning, budget allocation, funnel forecasters, email ROI, cohort analysis. Tools that make media buyers look like analysts.","title":"< ADS & MEDIA />","border_color":"neon-pink"}],"title":"What I Build","eyebrow":"// CALCULATOR_TYPES"},"block_type":"solution_cards"},{"data":{"title":"Why Calculators Convert","bullets":[{"icon":"🎯","text":"A visitor using your ROAS calculator is a buyer doing pre-sales research. Capture them at that moment — not after they leave.","title":"Intent Signal"},{"icon":"📧","text":"Every calculator I build includes an optional email gate: \"Email these results to yourself\" = email captured + results sent + follow-up sequence triggered.","title":"Built-In Lead Capture"},{"icon":"🧠","text":"The calculator teaches the buyer why your service creates ROI while showing them the exact numbers for their situation. No sales pitch required.","title":"Education That Sells"},{"icon":"🔗","text":"Where calculations need real data (Google Solar potential, current ad benchmarks, market rates), I connect to live APIs so the numbers are accurate.","title":"API-Backed for Accuracy"},{"icon":"📤","text":"Vite build outputs a self-contained JS bundle. Embed on WordPress, Webflow, Framer, or any page with one script tag.","title":"Embeddable Anywhere"},{"icon":"📊","text":"Every calculator submission is a tracked event. See which inputs users provide, where they drop off, and what results they see — in your own PostgreSQL.","title":"Analytics Built In"}]},"block_type":"icon_bullets"},{"data":{"body":"<p>The best calculator I have ever built for a client generated $180,000 in closed revenue in 90 days from a $6,000 build cost. It was a solar savings calculator: enter your address and monthly electric bill, get a 20-year savings projection and a form to book a consultation.</p><p class=\"mt-4\">The math was not complicated. The magic was the specificity: personalized numbers for that user''s specific house, electric rate, and sun exposure. Generic landing page copy says \"save up to 30% on electric bills.\" The calculator says \"Your house at 123 Main Street would generate $42,300 in electricity savings over 20 years.\"</p><p class=\"mt-4\">That specificity is worth the build cost many times over.</p><h3 class=\"text-white font-bold mt-6 mb-2\">Technical Architecture</h3><p>React 18 + TypeScript. State management with Zustand for complex multi-step tools. Recharts for visualizations. Vite for bundling (builds to a single JS file for easy embedding). PostgreSQL backend for storing results, tracking usage, and powering email-to-results features.</p>","title":"The Calculator as a Sales Tool"},"block_type":"value_prop"},{"data":{"section_title":"See Live Calculator Examples"},"block_type":"calculator"},{"data":{"title":"Scope Your Calculator Project","subhead":"Tell me what your buyers are trying to calculate. I''ll design the tool around the conversion goal.","form_title":"CALCULATOR_SCOPE_PROTOCOL","submit_source":"ChrisAmayaWork-Calculators"},"block_type":"audit_form"},{"data":{"href":"#audit","text":"$3,000–$8,000 to build. First closed deal covers the cost.","label":"Let''s Scope the Tool","heading":"Your Calculator Will Pay for Itself."},"block_type":"cta"}]'::jsonb,
  'emerald',
  '{"cta":{"href":"#audit","label":"INITIATE_HANDSHAKE"},"portfolio":[{"href":"/#hook","name":"The Problem"},{"href":"/#solution","name":"Architecture"},{"href":"/blog","name":"Blog & Knowledge Base"},{"href":"/guide/how-i-build","name":"How I Build"},{"href":"/search","name":"Search"}],"custom_apps":[{"href":"/services/custom-apps/python-api","name":"Python & FastAPI"},{"href":"/services/custom-apps/frontend","name":"Astro & React"},{"href":"/services/custom-apps/full-stack","name":"Full-Stack"},{"href":"/services/custom-apps/database","name":"PostgreSQL"},{"href":"/services/custom-apps/google-apis","name":"Google APIs"},{"href":"/services/custom-apps/wordpress","name":"WordPress"},{"href":"/services/custom-apps/calculators","name":"Calculators"},{"href":"/services/custom-apps/3d-visual","name":"3D & Visual"}],"growth_tools":[{"href":"https://jumpstartscaling.com","name":"Jumpstart Scaling"},{"href":"https://jumpstartscaling.com/services/growth-retainer","name":"Growth Retainer"},{"href":"https://jumpstartscaling.com/services/crm-transformation","name":"CRM Build"}]}'::jsonb,
  '{"tagline":"The Unicorn Developer.","copyright":"Chris Amaya"}'::jsonb
)
