  title = EXCLUDED.title, blocks = EXCLUDED.blocks,
  palette = EXCLUDED.palette, nav = EXCLUDED.nav, footer = EXCLUDED.footer;

INSERT INTO caw_content (slug, title, blocks, palette, nav, footer)
VALUES (
  'services/custom-apps/database',
  'PostgreSQL Schema Design & Database Architecture | Chris Amaya',
  '[{"data":{"badge":"DATABASE // POSTGRESQL","subhead":"Schema design, migrations, RLS multi-tenancy, pgvector AI search, and asyncpg integration. Production PostgreSQL from day one — not refactored when things break.","cta_href":"#audit","headline":"PostgreSQL<br class=\"hidden md:block\"/>Designed<br class=\"hidden md:block\"/><span class=\"text-neon\">For Scale.</span>","cta_label":"< DESIGN_MY_SCHEMA />"},"block_type":"hero"},{"data":{"cards":[{"body":"Normalized tables, JSONB for flexible fields, proper foreign keys, check constraints, and indexes that match your actual query patterns.","title":"< SCHEMA_DESIGN />","border_color":"neon-blue"},{"body":"Row-Level Security policies that enforce tenant isolation at the database level. No application-layer WHERE clauses that can be bypassed.","title":"< MULTI-TENANT_RLS />","border_color":"neon-green"},{"body":"pgvector extension for semantic similarity search. Knowledge base search, product recommendations, and AI RAG without a separate vector database.","title":"< AI_VECTOR_SEARCH />","border_color":"neon-pink"}],"title":"What I Design & Build","eyebrow":"// POSTGRESQL_CAPABILITIES"},"block_type":"solution_cards"},{"data":{"title":"PostgreSQL Skills I Bring","bullets":[{"icon":"🗄️","text":"Relational normalization, JSONB for semi-structured data, proper indexing strategy, and constraint design that enforces business rules at the DB level.","title":"Schema Design"},{"icon":"🔐","text":"PostgreSQL RLS for multi-tenant apps. Tenant ID propagated via JWT claim, enforced by policy. Even raw psql access cannot see other tenant data.","title":"Row-Level Security"},{"icon":"🧠","text":"Vector embeddings stored in PostgreSQL. Semantic search, RAG pipelines, and AI recommendation engines without Pinecone or Weaviate.","title":"pgvector"},{"icon":"⚡","text":"EXPLAIN ANALYZE, partial indexes, covering indexes, connection pooling with PgBouncer, and query optimization for tables with 50M+ rows.","title":"Performance Tuning"},{"icon":"📦","text":"Version-controlled schema migrations with zero-downtime strategies: adding columns, creating indexes concurrently, and backfilling data safely.","title":"Migrations"},{"icon":"🔄","text":"Logical replication for read replicas, pg_dump automation, and point-in-time recovery configuration for production databases.","title":"Replication & Backup"}]},"block_type":"icon_bullets"},{"data":{"body":"<p>The database schema is the most important architectural decision in any system. Get it wrong and every feature built on top inherits the debt. Get it right and the application layer becomes almost trivial.</p><p class=\"mt-4\">I start every project with a schema document before writing any application code. The questions I answer first: What are the entities? What are the relationships? Which fields need to be indexed? Where can JSONB replace a normalized table without sacrificing query ability?</p><p class=\"mt-4\"><strong class=\"text-white\">On JSONB vs Relational:</strong> I use JSONB for data where the shape varies by row — page content, block configurations, metadata. I use normalized tables for data that needs to be queried, filtered, or joined — users, orders, leads. The combination gives you document database flexibility with relational integrity.</p><p class=\"mt-4\"><strong class=\"text-white\">On ORM vs asyncpg:</strong> For high-throughput backends I skip SQLAlchemy and write SQL directly with asyncpg. The reason is simple: ORMs abstract the query, which means you cannot optimize what you cannot see. asyncpg forces you to write the query you mean, and the performance difference at scale is 3–5x.</p>","title":"My PostgreSQL Philosophy"},"block_type":"value_prop"},{"data":{"body":"These problems appear in 80% of the codebases I review. They compound over time into multi-day outages.","title":"Database Mistakes I Fix on Every Audit","bullets":["⚠ Missing indexes on foreign keys — table scans on every JOIN","⚠ N+1 queries from ORMs — 500 queries per page load","⚠ No connection pooling — DB connections exhausted under load","⚠ Sequences not cached — INSERT bottleneck at 10k rows/sec","⚠ RLS missing — application WHERE clause as only tenant barrier"],"eyebrow":"// DB_ANTI_PATTERNS","status_text":"_ INDEX_APPLIED: QUERY_NOMINAL","terminal_logs":[{"msg":"[SLOW] SELECT with JOIN on unindexed FK: 2,400ms avg","time":"BEFORE"},{"msg":"[MIGRATION] CREATE INDEX CONCURRENTLY idx_leads_tenant_id","time":"FIX"},{"msg":"[OK] Same query: 4ms avg. 99.8% improvement.","time":"AFTER"}]},"block_type":"terminal_problem"},{"data":{"title":"Database Architecture Review","subhead":"Share your current schema. I''ll find the bottlenecks and design the fix.","form_title":"SCHEMA_REVIEW_PROTOCOL","submit_source":"ChrisAmayaWork-Database"},"block_type":"audit_form"},{"data":{"href":"#audit","text":"Most performance problems are schema problems. Let''s fix the foundation.","label":"Book a Schema Review","heading":"Your Database Is the Foundation."},"block_type":"cta"}]'::jsonb,
  'emerald',
  '{"cta":{"href":"#audit","label":"INITIATE_HANDSHAKE"},"portfolio":[{"href":"/#hook","name":"The Problem"},{"href":"/#solution","name":"Architecture"},{"href":"/blog","name":"Blog & Knowledge Base"},{"href":"/guide/how-i-build","name":"How I Build"},{"href":"/search","name":"Search"}],"custom_apps":[{"href":"/services/custom-apps/python-api","name":"Python & FastAPI"},{"href":"/services/custom-apps/frontend","name":"Astro & React"},{"href":"/services/custom-apps/full-stack","name":"Full-Stack"},{"href":"/services/custom-apps/database","name":"PostgreSQL"},{"href":"/services/custom-apps/google-apis","name":"Google APIs"},{"href":"/services/custom-apps/wordpress","name":"WordPress"},{"href":"/services/custom-apps/calculators","name":"Calculators"},{"href":"/services/custom-apps/3d-visual","name":"3D & Visual"}],"growth_tools":[{"href":"https://jumpstartscaling.com","name":"Jumpstart Scaling"},{"href":"https://jumpstartscaling.com/services/growth-retainer","name":"Growth Retainer"},{"href":"https://jumpstartscaling.com/services/crm-transformation","name":"CRM Build"}]}'::jsonb,
  '{"tagline":"The Unicorn Developer.","copyright":"Chris Amaya"}'::jsonb
)
ON CONFLICT (slug) DO UPDATE SET
  title = EXCLUDED.title, blocks = EXCLUDED.blocks,
  palette = EXCLUDED.palette, nav = EXCLUDED.nav, footer = EXCLUDED.footer;

INSERT INTO caw_content (slug, title, blocks, palette, nav, footer)
VALUES (
  'services/custom-apps/frontend',
  'Astro, React & Vite | Custom Frontend Development | Chris Amaya',
  '[{"data":{"badge":"FRONTEND // ASTRO & REACT","subhead":"Astro SSR for marketing sites. React for dashboards and interactive tools. Vite for SPA and micro-frontend architecture. Lighthouse 95+ by default.","cta_href":"#audit","headline":"Frontend That<br class=\"hidden md:block\"/>Loads Fast<br class=\"hidden md:block\"/><span class=\"text-neon\">And Converts.</span>","cta_label":"< BUILD_MY_FRONTEND />"},"block_type":"hero"},{"data":{"cards":[{"body":"Marketing sites, landing pages, blog + KB systems. HTML ships to the browser. React islands only where needed. Sub-second LCP. Lighthouse 95–100.","title":"< ASTRO SSR />","border_color":"neon-blue"},{"body":"Client portals, admin dashboards, complex forms, calculator tools. React 18 with server components where applicable. Tailwind + shadcn/ui.","title":"< REACT APPS />","border_color":"neon-green"},{"body":"Embeddable widgets, calculator iframes, and SPAs that need fast HMR and tree-shaken bundles under 50kb.","title":"< VITE MICRO-APPS />","border_color":"neon-pink"}],"title":"Three Frontend Modes","eyebrow":"// FRONTEND_STACK"},"block_type":"solution_cards"},{"data":{"title":"What I Build for Clients","bullets":[{"icon":"🚀","text":"Agency sites, SaaS landing pages, and portfolio sites. SSR with CMS-driven content. Conversion-optimized layout. Lighthouse 100.","title":"Marketing Sites (Astro)"},{"icon":"📊","text":"Analytics dashboards, client portals, and internal tools. Real-time data via WebSocket. Recharts for visualization.","title":"Dashboards (React)"},{"icon":"🧮","text":"ROAS, CAC, LTV, ROI calculators. Embeddable on any site. API-backed for logged calculations. Lead capture built in.","title":"Calculator Tools (React/Vite)"},{"icon":"📰","text":"Astro or React consuming WordPress REST API, Sanity, or a custom PostgreSQL CMS. Content editable without code changes.","title":"Headless CMS Frontends"},{"icon":"🎨","text":"Tailwind-based component libraries. Consistent tokens, dark mode, and component documentation.","title":"Design System Implementation"},{"icon":"⚡","text":"Core Web Vitals audit and fix. LCP, CLS, INP. Image optimization, font loading, JS reduction. Lighthouse 40 → 95+.","title":"Performance Optimization"}]},"block_type":"icon_bullets"},{"data":{"body":"<p>Next.js is a great framework for app development. For marketing sites it ships too much JavaScript. A page that should be 40kb of HTML ends up being 300kb of JS because of the Next.js runtime.</p><p class=\"mt-4\">Astro solves this with the island architecture: HTML by default, JavaScript only where the component needs it. A Astro marketing site with a React contact form will ship zero JavaScript to pages that do not need the form.</p><p class=\"mt-4\">The result: LCP under 1 second, Lighthouse scores in the 95–100 range, and a Core Web Vitals pass without heroic optimization effort. For a client site where every second of load time costs conversions, this matters.</p><p class=\"mt-4\"><strong class=\"text-white\">When I use React instead:</strong> dashboards, interactive calculators, real-time data apps, anything with complex client state. React 18 + server components for the best of both worlds.</p>","title":"Why Astro Over Next.js for Marketing"},"block_type":"value_prop"},{"data":{"body":"After auditing dozens of marketing sites the problems follow a pattern. Performance is always the first casualty.","title":"What Is Broken in Most Agency Sites","bullets":["⚠ 400kb+ JavaScript bundle on a page with no interactivity","⚠ No image optimization — 4MB hero images blocking LCP","⚠ Google Fonts blocking render — 600ms font download before first paint","⚠ No OG tags, no schema markup, no canonical URLs"],"eyebrow":"// COMMON_FRONTEND_PROBLEMS","status_text":"_ AFTER_REBUILD: LIGHTHOUSE_98","terminal_logs":[{"msg":"[WARN] LCP: 4.8s (threshold: 2.5s) — Hero image unoptimized","time":"AUDIT"},{"msg":"[WARN] JS bundle: 412kb gzipped — 90% unused on initial load","time":"AUDIT"},{"msg":"[FAIL] No schema markup. Missing LocalBusiness JSON-LD.","time":"AUDIT"},{"msg":"[OK] After Astro rebuild: LCP 0.9s, JS 12kb, Lighthouse 98.","time":"FIX"}]},"block_type":"terminal_problem"},{"data":{"title":"Scope Your Frontend Project","subhead":"Tell me what you''re building. I''ll recommend the right stack and timeline.","form_title":"SCOPE_FRONTEND_PROTOCOL","submit_source":"ChrisAmayaWork-Frontend"},"block_type":"audit_form"},{"data":{"href":"#audit","text":"From Lighthouse 40 to 98. From 4-second loads to under 1 second.","label":"Get a Frontend Audit","heading":"Frontend That Performs and Converts."},"block_type":"cta"}]'::jsonb,
  'emerald',
  '{"cta":{"href":"#audit","label":"INITIATE_HANDSHAKE"},"portfolio":[{"href":"/#hook","name":"The Problem"},{"href":"/#solution","name":"Architecture"},{"href":"/blog","name":"Blog & Knowledge Base"},{"href":"/guide/how-i-build","name":"How I Build"},{"href":"/search","name":"Search"}],"custom_apps":[{"href":"/services/custom-apps/python-api","name":"Python & FastAPI"},{"href":"/services/custom-apps/frontend","name":"Astro & React"},{"href":"/services/custom-apps/full-stack","name":"Full-Stack"},{"href":"/services/custom-apps/database","name":"PostgreSQL"},{"href":"/services/custom-apps/google-apis","name":"Google APIs"},{"href":"/services/custom-apps/wordpress","name":"WordPress"},{"href":"/services/custom-apps/calculators","name":"Calculators"},{"href":"/services/custom-apps/3d-visual","name":"3D & Visual"}],"growth_tools":[{"href":"https://jumpstartscaling.com","name":"Jumpstart Scaling"},{"href":"https://jumpstartscaling.com/services/growth-retainer","name":"Growth Retainer"},{"href":"https://jumpstartscaling.com/services/crm-transformation","name":"CRM Build"}]}'::jsonb,
  '{"tagline":"The Unicorn Developer.","copyright":"Chris Amaya"}'::jsonb
)
ON CONFLICT (slug) DO UPDATE SET
  title = EXCLUDED.title, blocks = EXCLUDED.blocks,
  palette = EXCLUDED.palette, nav = EXCLUDED.nav, footer = EXCLUDED.footer;

INSERT INTO caw_content (slug, title, blocks, palette, nav, footer)
VALUES (
  'services/custom-apps/full-stack',
  'Full-Stack Architecture | Astro + FastAPI | Chris Amaya',
  '[{"data":{"badge":"FULL-STACK // ASTRO + FASTAPI","subhead":"DB-driven, multi-tenant, self-hosted. The God Mode architecture: Astro SSR on the frontend, FastAPI + PostgreSQL on the backend, Coolify for deployment.","cta_href":"#audit","headline":"One Architect.<br class=\"hidden md:block\"/>One Codebase.<br class=\"hidden md:block\"/><span class=\"text-neon\">One Invoice.</span>","cta_label":"< ARCHITECTURE_REVIEW />"},"block_type":"hero"},{"data":{"cards":[{"body":"PostgreSQL as the single source of truth. JSONB for flexible content. pgvector for AI search. RLS for multi-tenant isolation. asyncpg for zero-ORM speed.","title":"< DATA_LAYER />","border_color":"neon-blue"},{"body":"FastAPI with Python. Auto-documented endpoints. JWT auth. Background task queue. Webhook processing. CAPI relay. Pydantic validation throughout.","title":"< API_LAYER />","border_color":"neon-green"},{"body":"Astro SSR reads from DB at request time. React islands for interactive components. Content updates without redeploy. EJS for ultra-fast server rendering.","title":"< FRONTEND_LAYER />","border_color":"neon-pink"}],"title":"The God Mode Full-Stack Template","eyebrow":"// THE_ARCHITECTURE"},"block_type":"solution_cards"},{"data":{"body":"<p>This site is a live example of the architecture I sell. Every page on chrisamaya.work is stored in a PostgreSQL table called <code class=\"text-neon\">caw_content</code>. When you load /about, Fastify queries the database, gets a JSON array of blocks, renders them to HTML with a JS template function, and serves the result.</p><p class=\"mt-4\"><strong class=\"text-white\">Zero redeploy needed for content changes.</strong> When I update the about page copy, I update a row in <code class=\"text-neon\">caw_content</code>. The next request serves the new content. The container never restarts.</p><p class=\"mt-4\">The schema is four columns: <code class=\"text-neon\">slug</code>, <code class=\"text-neon\">title</code>, <code class=\"text-neon\">blocks</code> (JSONB), and <code class=\"text-neon\">nav</code> (JSONB). The server reads the blocks array and maps each <code class=\"text-neon\">block_type</code> to a render function. Add a new block type by adding a case to the switch statement — no framework, no build step, no deploy needed.</p>","title":"How chrisamaya.work Works (Real Example)"},"block_type":"value_prop"},{"data":{"title":"Full-Stack Use Cases","bullets":[{"icon":"🏢","text":"One codebase serving multiple clients. Row-Level Security in PostgreSQL isolates data. JWT identifies tenant on every request.","title":"Multi-Tenant SaaS"},{"icon":"📰","text":"Content stored in PostgreSQL. Pages update without redeploy. Admin UI is a simple SQL interface or a custom dashboard.","title":"DB-Driven CMS Sites"},{"icon":"🤖","text":"FastAPI orchestrates LLMs. pgvector for semantic search. Astro serves the results. Full AI product without third-party SaaS.","title":"AI-Powered Products"},{"icon":"📊","text":"FastAPI aggregates from PostgreSQL. React frontend visualizes in real time. No Tableau. No Metabase. Custom and owned.","title":"Analytics Dashboards"},{"icon":"🔗","text":"Public API for partners + private portal for clients. One PostgreSQL database. Two surfaces. One codebase to maintain.","title":"API + Portal Combos"},{"icon":"🛒","text":"PostgreSQL as the product catalog. FastAPI as the cart/order API. Astro or React as the storefront. No Shopify dependency.","title":"Headless Commerce"}]},"block_type":"icon_bullets"},{"data":{"body":"The most common failure mode: technology chosen before architecture is defined. The stack fights itself from day one.","title":"What Breaks in Typical Full-Stack Projects","bullets":["⚠ Mixing REST and GraphQL without a contract — N+1 queries everywhere","⚠ ORM chosen for developer convenience, kills performance at 100k rows","⚠ Frontend state and backend state diverge — cache invalidation nightmares","⚠ Multi-tenancy bolted on after launch — data isolation retrofitted is insecure"],"eyebrow":"// ARCHITECTURE_AUDIT","status_text":"_ ARCHITECTURE_FIRST: ZERO_TECHNICAL_DEBT","terminal_logs":[{"msg":"[OK] Schema finalized. RLS policies written. No tenant can read another tenant''s data.","time":"DESIGN"},{"msg":"[OK] API contract defined. OpenAPI spec approved. No ambiguity.","time":"DESIGN"},{"msg":"[OK] asyncpg pool configured. Query time avg 8ms on 1M row table.","time":"BUILD"},{"msg":"[OK] Zero-downtime deploy via Coolify container swap.","time":"DEPLOY"}]},"block_type":"terminal_problem"},{"data":{"title":"Architecture Review for Your Full-Stack Product","subhead":"Describe what you''re building and where the current architecture breaks.","form_title":"ARCHITECTURE_REVIEW_PROTOCOL","submit_source":"ChrisAmayaWork-FullStack"},"block_type":"audit_form"},{"data":{"href":"#audit","text":"Architecture doc in 48 hours. First production deploy by day 14. Two Q1 slots.","label":"Book an Architecture Review","heading":"Ship a Production Full-Stack System in 14 Days."},"block_type":"cta"}]'::jsonb,
  'emerald',
  '{"cta":{"href":"#audit","label":"INITIATE_HANDSHAKE"},"portfolio":[{"href":"/#hook","name":"The Problem"},{"href":"/#solution","name":"Architecture"},{"href":"/blog","name":"Blog & Knowledge Base"},{"href":"/guide/how-i-build","name":"How I Build"},{"href":"/search","name":"Search"}],"custom_apps":[{"href":"/services/custom-apps/python-api","name":"Python & FastAPI"},{"href":"/services/custom-apps/frontend","name":"Astro & React"},{"href":"/services/custom-apps/full-stack","name":"Full-Stack"},{"href":"/services/custom-apps/database","name":"PostgreSQL"},{"href":"/services/custom-apps/google-apis","name":"Google APIs"},{"href":"/services/custom-apps/wordpress","name":"WordPress"},{"href":"/services/custom-apps/calculators","name":"Calculators"},{"href":"/services/custom-apps/3d-visual","name":"3D & Visual"}],"growth_tools":[{"href":"https://jumpstartscaling.com","name":"Jumpstart Scaling"},{"href":"https://jumpstartscaling.com/services/growth-retainer","name":"Growth Retainer"},{"href":"https://jumpstartscaling.com/services/crm-transformation","name":"CRM Build"}]}'::jsonb,
  '{"tagline":"The Unicorn Developer.","copyright":"Chris Amaya"}'::jsonb
)
ON CONFLICT (slug) DO UPDATE SET
  title = EXCLUDED.title, blocks = EXCLUDED.blocks,
  palette = EXCLUDED.palette, nav = EXCLUDED.nav, footer = EXCLUDED.footer;

INSERT INTO caw_content (slug, title, blocks, palette, nav, footer)
VALUES (
  'services/custom-apps/google-apis',
  'Google Solar, Roofing & Maps API | Custom Integration | Chris Amaya',
  '[{"data":{"badge":"GOOGLE APIS // SOLAR & MAPS","subhead":"Solar potential, rooftop data, Maps, Places, Geocoding, and Directions. I build custom applications on top of Google''s geo and energy APIs — not toy demos but production products.","cta_href":"#audit","headline":"Google APIs.<br class=\"hidden md:block\"/>Custom Apps.<br class=\"hidden md:block\"/><span class=\"text-neon\">Actual Value.</span>","cta_label":"< EXPLORE_INTEGRATIONS />"},"block_type":"hero"},{"data":{"cards":[{"body":"Google Solar API: solar potential by address, rooftop segment data, energy output estimates, and financial model data for quote tools and lead capture apps.","title":"< SOLAR & ROOFING />","border_color":"neon-blue"},{"body":"Maps JavaScript API, Places Autocomplete, Geocoding, Directions, Distance Matrix. Service area calculators, franchise locators, route optimizers.","title":"< MAPS & GEO />","border_color":"neon-green"},{"body":"React dashboards consuming multiple Google APIs. Real-time data, cached in PostgreSQL to save API costs, refreshed on schedule via n8n automation.","title":"< CUSTOM_DASHBOARDS />","border_color":"neon-pink"}],"title":"Google API Integrations I Build","eyebrow":"// API_CAPABILITIES"},"block_type":"solution_cards"},{"data":{"title":"Google API Use Cases I Have Shipped","bullets":[{"icon":"☀️","text":"Enter an address, get solar panel capacity, estimated kWh output, 20-year savings projection, and a lead capture form. Built for solar installers.","title":"Solar Potential Tool"},{"icon":"🏠","text":"Google Roofing API + Maps + custom measurement logic. Automated roof size estimation with aerial imagery. Replaces manual site visits for initial quotes.","title":"Roofing Quote Calculator"},{"icon":"📍","text":"Places API + custom radius logic. Customers enter zip code, see if they''re in your service area, and book directly. CRM integration included.","title":"Service Area Locator"},{"icon":"🗺️","text":"Directions + Distance Matrix API for field service companies. Optimized daily routes for technicians, with live updates and drive time estimates.","title":"Route Optimizer"},{"icon":"🏢","text":"Geocoding + business data overlay. Map your customer base, franchise distribution, or competitor locations with custom data layers.","title":"Location Intelligence"},{"icon":"📊","text":"Visualize sales, service calls, or site performance on a Google Map. Heat maps, cluster markers, and filters — all custom, no Google Looker required.","title":"Analytics + Maps Dashboard"}]},"block_type":"icon_bullets"},{"data":{"body":"<p>Google''s geo and energy APIs are the most accurate in the world — updated daily with satellite imagery, real-time traffic, and building footprint data. For businesses in solar, roofing, home services, real estate, and field operations, they are not optional. They are the data layer.</p><p class=\"mt-4\">The problem is most vendors selling \"Google Maps integration\" mean dropping a map embed on a page. I mean building a full application that consumes the API programmatically: geocoding addresses in bulk, pulling solar potential data for a ZIP code''s entire lead list, or routing 50 technicians optimally every morning.</p><p class=\"mt-4\"><strong class=\"text-white\">Cost optimization:</strong> Google API calls cost money at scale. I always build a PostgreSQL caching layer — addresses are geocoded once and stored. Solar data for a ZIP code is cached for 24 hours. Route matrices are computed once per day. Clients typically see 70–90% API cost reduction vs. calling Google on every user action.</p>","title":"Why Google Geo APIs for Your Business"},"block_type":"value_prop"},{"data":{"title":"Scope Your Google API Project","subhead":"Tell me what data you need from Google. I''ll design the app around it.","form_title":"SCOPE_GAPI_PROTOCOL","submit_source":"ChrisAmayaWork-GoogleAPIs"},"block_type":"audit_form"},{"data":{"href":"#audit","text":"Solar potential tool. Route optimizer. Service area locator. What does your industry need?","label":"Scope the Project","heading":"Turn Google Data Into a Product."},"block_type":"cta"}]'::jsonb,
  'emerald',
  '{"cta":{"href":"#audit","label":"INITIATE_HANDSHAKE"},"portfolio":[{"href":"/#hook","name":"The Problem"},{"href":"/#solution","name":"Architecture"},{"href":"/blog","name":"Blog & Knowledge Base"},{"href":"/guide/how-i-build","name":"How I Build"},{"href":"/search","name":"Search"}],"custom_apps":[{"href":"/services/custom-apps/python-api","name":"Python & FastAPI"},{"href":"/services/custom-apps/frontend","name":"Astro & React"},{"href":"/services/custom-apps/full-stack","name":"Full-Stack"},{"href":"/services/custom-apps/database","name":"PostgreSQL"},{"href":"/services/custom-apps/google-apis","name":"Google APIs"},{"href":"/services/custom-apps/wordpress","name":"WordPress"},{"href":"/services/custom-apps/calculators","name":"Calculators"},{"href":"/services/custom-apps/3d-visual","name":"3D & Visual"}],"growth_tools":[{"href":"https://jumpstartscaling.com","name":"Jumpstart Scaling"},{"href":"https://jumpstartscaling.com/services/growth-retainer","name":"Growth Retainer"},{"href":"https://jumpstartscaling.com/services/crm-transformation","name":"CRM Build"}]}'::jsonb,
  '{"tagline":"The Unicorn Developer.","copyright":"Chris Amaya"}'::jsonb
)
ON CONFLICT (slug) DO UPDATE SET
  title = EXCLUDED.title, blocks = EXCLUDED.blocks,
  palette = EXCLUDED.palette, nav = EXCLUDED.nav, footer = EXCLUDED.footer;

INSERT INTO caw_content (slug, title, blocks, palette, nav, footer)
VALUES (
  'services/custom-apps/python-api',
  'Python & FastAPI | Custom Backend APIs | Chris Amaya',
  '[{"data":{"badge":"BACKEND // PYTHON & FASTAPI","subhead":"Async FastAPI + asyncpg + PostgreSQL. The same stack powering God Mode, Jumpstart Scaling, and every high-throughput system I have shipped.","cta_href":"#audit","headline":"Custom Python<br class=\"hidden md:block\"/>Backends That<br class=\"hidden md:block\"/><span class=\"text-neon\">Actually Scale.</span>","cta_label":"< DISCUSS_YOUR_API />","warning_text":"// Minimum engagement: $10k. Production-grade only."},"block_type":"hero"},{"data":{"cards":[{"body":"FastAPI with full OpenAPI docs generated automatically. REST, WebSocket, and SSE. Rate limiting, auth middleware, background tasks, and webhook receivers.","title":"< REST & WEBSOCKET APIs />","border_color":"neon-blue"},{"body":"asyncpg for blazing-fast PostgreSQL reads/writes. Batch processing, queue consumers, and ETL pipelines that handle millions of rows without choking.","title":"< ASYNC DATA PIPELINES />","border_color":"neon-green"},{"body":"LangChain, LlamaIndex, and bare OpenAI/Anthropic API. Agent pipelines, RAG with pgvector, and private LLM endpoints on your own infra.","title":"< AI ORCHESTRATION />","border_color":"neon-pink"}],"title":"Python Backend Capabilities","eyebrow":"// WHAT_I_BUILD"},"block_type":"solution_cards"},{"data":{"body":"I have built in Node, Go, and Python. For data-heavy, AI-adjacent backends, Python wins on every metric that matters in production.","title":"Why I Chose Python for Production Backends","bullets":["✓ FastAPI auto-generates OpenAPI docs — no manual spec writing","✓ asyncpg is 3x faster than SQLAlchemy for high-throughput reads","✓ Pydantic v2 validates every request/response at the type level","✓ Python''s AI/ML ecosystem is 5 years ahead of every other language","✓ Celery + Redis for background tasks that survive server restarts"],"eyebrow":"// WHY_FASTAPI_NOT_NODE","status_text":"_ PYTHON_BACKEND: PRODUCTION NOMINAL","terminal_logs":[{"msg":"asyncpg SELECT 10k rows: 12ms avg","time":"BENCHMARK"},{"msg":"FastAPI /health cold start: 8ms","time":"BENCHMARK"},{"msg":"Pydantic v2 validation 1k objects: 0.3ms","time":"BENCHMARK"},{"msg":"[OK] Webhook receiver: 2,400 events/min processed without queue backup","time":"PROD"}]},"block_type":"terminal_problem"},{"data":{"title":"Use Cases I Build For","bullets":[{"icon":"🔗","text":"Webhook receivers that sync leads from Facebook, Google, and landing pages into GHL, HubSpot, or a custom DB in real time.","title":"CRM Sync Engines"},{"icon":"🤖","text":"API layers that orchestrate private LLMs: lead scoring, email drafting, competitor analysis, proposal generation.","title":"AI Agent Backends"},{"icon":"📡","text":"Server-side conversion APIs for Facebook, Google, and TikTok. No pixel dependencies. Works through ad blockers and iOS14.","title":"CAPI / Tracking Servers"},{"icon":"🧮","text":"Financial calculators, ROAS models, LTV projections. Handles complex formulas with Pydantic-validated inputs and cached results.","title":"Calculation APIs"},{"icon":"🗄️","text":"Row-Level Security in PostgreSQL + JWT auth. Every tenant''s data isolated at the database level, not just the application layer.","title":"Multi-Tenant SaaS Backends"},{"icon":"⚙️","text":"n8n webhook targets, Airtable replacements, and custom API backends for no-code tools that have outgrown their hosts.","title":"Automation Backends"}]},"block_type":"icon_bullets"},{"data":{"body":"<p><strong class=\"text-white\">FastAPI 0.110+</strong> — Async Python web framework. Auto-generated OpenAPI/Swagger docs. Dependency injection for auth, DB connections, and rate limiting. Background tasks without Celery for simple cases.</p><p class=\"mt-4\"><strong class=\"text-white\">asyncpg + PostgreSQL 16</strong> — Direct PostgreSQL driver without ORM overhead. 3x faster than SQLAlchemy for read-heavy workloads. JSONB columns for flexible schema. pgvector extension for AI semantic search.</p><p class=\"mt-4\"><strong class=\"text-white\">Pydantic v2</strong> — Request/response validation at the type system level. Invalid data never reaches your business logic. Errors surface at the API boundary with clear messages.</p><p class=\"mt-4\"><strong class=\"text-white\">Deployment: Coolify + Docker</strong> — FastAPI in an Alpine container. Git push to deploy. Gunicorn + Uvicorn workers. Health checks. Zero downtime deploys via container swap.</p>","title":"The Tech Stack in Detail"},"block_type":"value_prop"},{"data":{"body":"<p>God Mode API — the backend powering Jumpstart Scaling''s factory: multi-tenant content generation, async job queues, and PostgreSQL as a document store. Handles bulk AI generation without dropping requests.</p><p class=\"mt-4\">Solar roofing API — Google Solar API integration for a regional solar installer. Postal code lookup → solar potential calculation → lead capture API → CRM sync. 200ms response time on production.</p>","stats":[{"label":"APIs Shipped","value":"50+"},{"label":"Median API Response","value":"<15ms"},{"label":"Uptime on Coolify","value":"99.9%"}],"title":"Systems I Have Shipped"},"block_type":"authority"},{"data":{"title":"Scope Your Python Backend","subhead":"Tell me what the API needs to do. I''ll tell you how long it takes to build.","form_title":"SCOPE_API_PROTOCOL","submit_source":"ChrisAmayaWork-PythonAPI"},"block_type":"audit_form"},{"data":{"href":"#audit","text":"14-day delivery from approved architecture doc to deployed API.","label":"Book a Scoping Call","heading":"Need a Production-Grade Python Backend?"},"block_type":"cta"}]'::jsonb,
  'emerald',
  '{"cta":{"href":"#audit","label":"INITIATE_HANDSHAKE"},"portfolio":[{"href":"/#hook","name":"The Problem"},{"href":"/#solution","name":"Architecture"},{"href":"/blog","name":"Blog & Knowledge Base"},{"href":"/guide/how-i-build","name":"How I Build"},{"href":"/search","name":"Search"}],"custom_apps":[{"href":"/services/custom-apps/python-api","name":"Python & FastAPI"},{"href":"/services/custom-apps/frontend","name":"Astro & React"},{"href":"/services/custom-apps/full-stack","name":"Full-Stack"},{"href":"/services/custom-apps/database","name":"PostgreSQL"},{"href":"/services/custom-apps/google-apis","name":"Google APIs"},{"href":"/services/custom-apps/wordpress","name":"WordPress"},{"href":"/services/custom-apps/calculators","name":"Calculators"},{"href":"/services/custom-apps/3d-visual","name":"3D & Visual"}],"growth_tools":[{"href":"https://jumpstartscaling.com","name":"Jumpstart Scaling"},{"href":"https://jumpstartscaling.com/services/growth-retainer","name":"Growth Retainer"},{"href":"https://jumpstartscaling.com/services/crm-transformation","name":"CRM Build"}]}'::jsonb,
  '{"tagline":"The Unicorn Developer.","copyright":"Chris Amaya"}'::jsonb
)
ON CONFLICT (slug) DO UPDATE SET
  title = EXCLUDED.title, blocks = EXCLUDED.blocks,
  palette = EXCLUDED.palette, nav = EXCLUDED.nav, footer = EXCLUDED.footer;

INSERT INTO caw_content (slug, title, blocks, palette, nav, footer)
VALUES (
  'services/custom-apps/wordpress',
  'Headless WordPress & Custom Plugin Development | Chris Amaya',
  '[{"data":{"badge":"WORDPRESS // HEADLESS & CUSTOM","subhead":"Headless WordPress with Astro or React frontends. Custom plugins, REST API extensions, WooCommerce, ACF, and WPGraphQL. Modern WordPress without the legacy baggage.","cta_href":"#audit","headline":"WordPress as<br class=\"hidden md:block\"/>a Platform,<br class=\"hidden md:block\"/><span class=\"text-neon\">Not a Limitation.</span>","cta_label":"< MODERNIZE_MY_WP />"},"block_type":"hero"},{"data":{"cards":[{"body":"WordPress as content management, Astro or React as the frontend. Best of both worlds: client-friendly WP admin, developer-friendly frontend with Lighthouse 95+.","title":"< HEADLESS_CMS />","border_color":"neon-blue"},{"body":"Custom post types, meta fields (ACF), REST API endpoints, WooCommerce extensions, and integrations with external APIs via custom plugins.","title":"< CUSTOM_PLUGINS />","border_color":"neon-green"},{"body":"Custom product types, checkout flows, payment gateway integration, subscription plugins, and headless WooCommerce with a React storefront.","title":"< WOOCOMMERCE />","border_color":"neon-pink"}],"title":"WordPress Development Services","eyebrow":"// WORDPRESS_SERVICES"},"block_type":"solution_cards"},{"data":{"title":"WordPress Use Cases I Build","bullets":[{"icon":"📰","text":"Editorial team stays in the WordPress admin they know. Frontend is Astro or React — fast, modern, and Lighthouse optimized. REST API or WPGraphQL as the bridge.","title":"Headless CMS Site"},{"icon":"🔌","text":"REST API endpoints for third-party integrations. Custom post types for non-blog content. ACF field groups for structured content entry.","title":"Custom Plugin"},{"icon":"🛒","text":"WooCommerce handles products, orders, and payments. React handles the storefront. No WordPress theme overhead. Checkout conversion rates increase.","title":"Headless WooCommerce"},{"icon":"🔗","text":"Custom plugin that pushes WooCommerce orders, contact form submissions, or custom events to GHL, HubSpot, or a FastAPI backend.","title":"CRM Integration Plugin"},{"icon":"📊","text":"Custom WP admin page showing revenue, conversion, and customer metrics pulled from WooCommerce database and external APIs.","title":"Analytics Dashboard"},{"icon":"⚡","text":"WordPress site doing 4 seconds LCP → under 1 second. Caching strategy, image optimization, query optimization, and plugin audit.","title":"Performance Overhaul"}]},"block_type":"icon_bullets"},{"data":{"body":"<p>WordPress powers 40% of the web. It is not going away. The editorial experience is unmatched for non-technical teams — custom fields via ACF, familiar admin UI, and decades of plugin ecosystem.</p><p class=\"mt-4\">The problem is WordPress as a rendering engine is slow. A standard WordPress + WooCommerce site with 20 plugins runs 200+ database queries per page load and clocks Lighthouse scores in the 40–60 range.</p><p class=\"mt-4\">The headless pattern solves this: WordPress manages content, a modern frontend framework handles rendering. REST API or WPGraphQL bridges the two. The content team works in WordPress. The user experiences a fast, modern frontend.</p><p class=\"mt-4\"><strong class=\"text-white\">When to stay with traditional WordPress:</strong> If the team needs the Gutenberg editor, if the site is content-heavy with complex editorial workflows, or if the budget does not support a full frontend rebuild. In these cases I optimize the traditional stack instead: caching, query optimization, CDN configuration.</p>","title":"The Case for Headless WordPress"},"block_type":"value_prop"},{"data":{"title":"WordPress Architecture Review","subhead":"Tell me what is broken or what you want to build. I''ll design the right approach.","form_title":"WP_REVIEW_PROTOCOL","submit_source":"ChrisAmayaWork-WordPress"},"block_type":"audit_form"},{"data":{"href":"#audit","text":"Headless, fast, and actually maintainable. Book a discovery call.","label":"Start a WP Discovery","heading":"WordPress Can Be Modern. Let''s Prove It."},"block_type":"cta"}]'::jsonb,
  'emerald',
  '{"cta":{"href":"#audit","label":"INITIATE_HANDSHAKE"},"portfolio":[{"href":"/#hook","name":"The Problem"},{"href":"/#solution","name":"Architecture"},{"href":"/blog","name":"Blog & Knowledge Base"},{"href":"/guide/how-i-build","name":"How I Build"},{"href":"/search","name":"Search"}],"custom_apps":[{"href":"/services/custom-apps/python-api","name":"Python & FastAPI"},{"href":"/services/custom-apps/frontend","name":"Astro & React"},{"href":"/services/custom-apps/full-stack","name":"Full-Stack"},{"href":"/services/custom-apps/database","name":"PostgreSQL"},{"href":"/services/custom-apps/google-apis","name":"Google APIs"},{"href":"/services/custom-apps/wordpress","name":"WordPress"},{"href":"/services/custom-apps/calculators","name":"Calculators"},{"href":"/services/custom-apps/3d-visual","name":"3D & Visual"}],"growth_tools":[{"href":"https://jumpstartscaling.com","name":"Jumpstart Scaling"},{"href":"https://jumpstartscaling.com/services/growth-retainer","name":"Growth Retainer"},{"href":"https://jumpstartscaling.com/services/crm-transformation","name":"CRM Build"}]}'::jsonb,
  '{"tagline":"The Unicorn Developer.","copyright":"Chris Amaya"}'::jsonb
)
ON CONFLICT (slug) DO UPDATE SET
  title = EXCLUDED.title, blocks = EXCLUDED.blocks,
  palette = EXCLUDED.palette, nav = EXCLUDED.nav, footer = EXCLUDED.footer;

INSERT INTO caw_content (slug, title, blocks, palette, nav, footer)
VALUES (
  'terms',
  'Terms of Service | Chris Amaya',
  '[{"data":{"badge":"LEGAL // TERMS OF SERVICE","subhead":"Effective date: January 1, 2025. These terms govern use of chrisamaya.work and any services provided by Chris Amaya.","cta_href":"/contact","headline":"Terms of<br class=\"hidden md:block\"/><span class=\"text-neon\">Service.</span>","cta_label":"Contact"},"block_type":"hero"},{"data":{"body":"<p>Chris Amaya (\"I\", \"me\", \"Architect\") provides custom software architecture, backend development, frontend development, database design, AI integration, and related technical consulting services (\"Services\") to clients (\"you\", \"Client\").</p><h3 class=\"text-white font-bold mt-6 mb-2\">2. Engagement Terms</h3><p>All engagements begin with a signed Statement of Work (SOW) or engagement agreement. No work begins without written agreement on scope, timeline, and payment terms.</p><h3 class=\"text-white font-bold mt-6 mb-2\">3. Payment</h3><p>Projects are invoiced 50% upfront, 50% on delivery unless otherwise agreed in writing. Retainers are billed monthly in advance. Overdue invoices accrue 1.5% monthly interest after 15 days.</p><h3 class=\"text-white font-bold mt-6 mb-2\">4. Intellectual Property</h3><p>Upon receipt of final payment, all custom code written for a project transfers to the Client. Open-source components, third-party libraries, and reusable architectural patterns remain property of Chris Amaya unless specifically contracted otherwise.</p><h3 class=\"text-white font-bold mt-6 mb-2\">5. Confidentiality</h3><p>I treat all client information as confidential. I do not share source code, business data, or system architecture with third parties. Clients are encouraged to include an NDA in any engagement agreement for additional protection.</p><h3 class=\"text-white font-bold mt-6 mb-2\">6. Limitation of Liability</h3><p>My liability for any claim arising from services provided shall not exceed the total fees paid in the 30 days prior to the claim. I am not liable for indirect, incidental, or consequential damages.</p><h3 class=\"text-white font-bold mt-6 mb-2\">7. Governing Law</h3><p>These terms are governed by the laws of the State of Texas, United States. Disputes shall be resolved through binding arbitration in Austin, TX.</p><h3 class=\"text-white font-bold mt-6 mb-2\">8. Changes to Terms</h3><p>I may update these terms at any time. Continued use of this site or services after changes constitutes acceptance. Material changes will be communicated to active clients via email.</p><h3 class=\"text-white font-bold mt-6 mb-2\">9. Contact</h3><p>Questions about these terms? Email via the <a href=\"/contact\" class=\"text-neon\">contact page</a>.</p>","title":"1. Services"},"block_type":"value_prop"},{"data":{"href":"/contact","text":"Let''s talk scope, timeline, and fit.","label":"Book a Call","heading":"Questions About a Project?"},"block_type":"cta"}]'::jsonb,
  'emerald',
  '{"cta":{"href":"#audit","label":"INITIATE_HANDSHAKE"},"portfolio":[{"href":"/#hook","name":"The Problem"},{"href":"/#solution","name":"Architecture"},{"href":"/blog","name":"Blog & Knowledge Base"},{"href":"/guide/how-i-build","name":"How I Build"},{"href":"/search","name":"Search"}],"custom_apps":[{"href":"/services/custom-apps/python-api","name":"Python & FastAPI"},{"href":"/services/custom-apps/frontend","name":"Astro & React"},{"href":"/services/custom-apps/full-stack","name":"Full-Stack"},{"href":"/services/custom-apps/database","name":"PostgreSQL"},{"href":"/services/custom-apps/google-apis","name":"Google APIs"},{"href":"/services/custom-apps/wordpress","name":"WordPress"},{"href":"/services/custom-apps/calculators","name":"Calculators"},{"href":"/services/custom-apps/3d-visual","name":"3D & Visual"}],"growth_tools":[{"href":"https://jumpstartscaling.com","name":"Jumpstart Scaling"},{"href":"https://jumpstartscaling.com/services/growth-retainer","name":"Growth Retainer"},{"href":"https://jumpstartscaling.com/services/crm-transformation","name":"CRM Build"}]}'::jsonb,
  '{"tagline":"The Unicorn Developer.","copyright":"Chris Amaya"}'::jsonb
)
